## Fase 7: Proteção de Rotas por Role

### Task 7.1: Criar hook useSpacePermissions

**Files:**
- Create: `src/lib/hooks/useSpacePermissions.ts`

**Step 1: Implementar hook**

```typescript
// src/lib/hooks/useSpacePermissions.ts
'use client'

import { useState, useEffect } from 'react'

type Permissions = {
  canViewTransactions: boolean
  canEditTransactions: boolean
  canViewAllTransactions: boolean
  canViewInvestments: boolean
  canViewBudgets: boolean
  canManageSpace: boolean
  canViewIncomes: boolean
  isSpaceContext: boolean
  role: string | null
}

export function useSpacePermissions(): Permissions & { loading: boolean } {
  const [permissions, setPermissions] = useState<Permissions>({
    canViewTransactions: true,
    canEditTransactions: true,
    canViewAllTransactions: true,
    canViewInvestments: true,
    canViewBudgets: true,
    canManageSpace: false,
    canViewIncomes: true,
    isSpaceContext: false,
    role: null,
  })
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    fetch('/api/spaces/active/permissions')
      .then((res) => res.json())
      .then(setPermissions)
      .finally(() => setLoading(false))
  }, [])

  return { ...permissions, loading }
}
```

**Step 2: Criar endpoint /api/spaces/active/permissions**

```typescript
// src/app/api/spaces/active/permissions/route.ts
import { NextResponse } from 'next/server'
import { getAuthContext } from '@/lib/auth-utils'
import { unauthorizedResponse } from '@/lib/auth-utils'

export async function GET() {
  try {
    const ctx = await getAuthContext()

    if (!ctx.spaceId || !ctx.permissions) {
      return NextResponse.json({
        canViewTransactions: true,
        canEditTransactions: true,
        canViewAllTransactions: true,
        canViewInvestments: true,
        canViewBudgets: true,
        canManageSpace: false,
        canViewIncomes: true,
        isSpaceContext: false,
        role: null,
      })
    }

    return NextResponse.json({
      canViewTransactions: ctx.permissions.canViewTransactions(),
      canEditTransactions: ctx.permissions.canEditTransactions(),
      canViewAllTransactions: ctx.permissions.canViewAllTransactions(),
      canViewInvestments: ctx.permissions.canViewInvestments(),
      canViewBudgets: ctx.permissions.canViewBudgets(),
      canManageSpace: ctx.permissions.canManageSpace(),
      canViewIncomes: ctx.permissions.canViewIncomes(),
      isSpaceContext: true,
      role: null, // role is internal
    })
  } catch (error) {
    if (error instanceof Error && error.message === 'Unauthorized') {
      return unauthorizedResponse()
    }
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}
```

