15→function createPrismaClient() {
16→  const connectionString = process.env.DATABASE_URL;
17→  if (!connectionString) {
18→    throw new Error("DATABASE_URL environment variable is not set");
19→  }
20→  const pool = new Pool({ connectionString });
21→  const adapter = new PrismaNeon(pool);
22→  return new PrismaClient({ adapter });
23→}
24→
25→// Lazy initialization - only create client when first accessed
26→function getPrismaClient() {
27→  if (!globalForPrisma.prisma) {
28→    globalForPrisma.prisma = createPrismaClient();
29→  }
30→  return globalForPrisma.prisma;
31→}
32→
33→// Export a proxy that lazily initializes prisma on first use
34→export const prisma = new Proxy({} as PrismaClient, {
35→  get(_, prop) {
36→    return getPrismaClient()[prop as keyof PrismaClient];
