  1→import { NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→interface PatternMatch {
  6→  description: string;
  7→  normalizedDescription: string;
  8→  avgAmount: number;
  9→  occurrences: number;
 10→  avgDayOfMonth: number;
 11→  categoryId: string | null;
 12→  categoryName: string | null;
 13→  origin: string;
 14→}
 15→
 16→function normalizeDescription(desc: string): string {
 17→  // Remove installment patterns like "1/10", "PARCELA 1 DE 10"
 18→  let normalized = desc
 19→    .replace(/\d+\s*(?:\/|DE)\s*\d+/gi, "")
 20→    .replace(/PARCELA/gi, "")
 21→    .trim();
 22→
 23→  // Remove common prefixes/suffixes that vary
 24→  normalized = normalized
 25→    .replace(/\s*-\s*\d+$/g, "")
 26→    .replace(/^\d+\s*-\s*/g, "")
 27→    .trim();
 28→
 29→  // Remove extra whitespace
 30→  normalized = normalized.replace(/\s+/g, " ").toUpperCase();
 31→
 32→  return normalized;
 33→}
 34→
 35→export async function GET() {
 36→  try {
 37→    const userId = await getAuthenticatedUserId();
 38→
 39→    // Get the last 6 months of transactions
 40→    const sixMonthsAgo = new Date();
 41→    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);
 42→
 43→    const transactions = await prisma.transaction.findMany({
 44→      where: {
 45→        date: { gte: sixMonthsAgo },
 46→        type: "EXPENSE",
 47→        isInstallment: false,
 48→        recurringExpenseId: null,
 49→        userId,
 50→      },
 51→      include: {
 52→        category: true,
 53→      },
 54→      orderBy: {
 55→        date: "desc",
 56→      },
 57→    });
 58→
 59→    // Get existing recurring expenses to exclude from suggestions
 60→    const existingRecurring = await prisma.recurringExpense.findMany({
 61→      where: { userId },
 62→      select: { description: true },
 63→    });
 64→    const existingDescriptions = new Set(
 65→      existingRecurring.map((r) => normalizeDescription(r.description))
 66→    );
 67→
 68→    // Group transactions by normalized description
 69→    const groups: Record<string, {
 70→      transactions: typeof transactions;
 71→      normalizedDesc: string;
 72→    }> = {};
 73→
 74→    for (const t of transactions) {
 75→      const normalized = normalizeDescription(t.description);
 76→      if (!normalized) continue;
 77→
 78→      if (!groups[normalized]) {
 79→        groups[normalized] = {
 80→          transactions: [],
 81→          normalizedDesc: normalized,
 82→        };
 83→      }
 84→      groups[normalized].transactions.push(t);
 85→    }
 86→
 87→    // Analyze patterns - look for transactions that appear 3+ times
 88→    const suggestions: PatternMatch[] = [];
 89→
 90→    for (const [key, group] of Object.entries(groups)) {
 91→      // Skip if this pattern already exists as a recurring expense
 92→      if (existingDescriptions.has(key)) continue;
 93→
 94→      // Need at least 3 occurrences to suggest
 95→      if (group.transactions.length < 3) continue;
 96→
 97→      // Check if they are in different months
 98→      const monthSet = new Set(
 99→        group.transactions.map((t) => {
100→          const d = new Date(t.date);
101→          return `${d.getFullYear()}-${d.getMonth()}`;
102→        })
103→      );
104→
105→      // Need at least 2 different months
106→      if (monthSet.size < 2) continue;
107→
108→      // Calculate average values
109→      const amounts = group.transactions.map((t) => Math.abs(t.amount));
110→      const avgAmount = amounts.reduce((a, b) => a + b, 0) / amounts.length;
111→
112→      const days = group.transactions.map((t) => new Date(t.date).getDate());
113→      const avgDayOfMonth = Math.round(
114→        days.reduce((a, b) => a + b, 0) / days.length
115→      );
116→
117→      // Use the most recent transaction for category and origin
118→      const latest = group.transactions[0];
119→
120→      suggestions.push({
121→        description: latest.description,
122→        normalizedDescription: key,
123→        avgAmount,
124→        occurrences: group.transactions.length,
125→        avgDayOfMonth,
126→        categoryId: latest.categoryId,
127→        categoryName: latest.category?.name || null,
128→        origin: latest.origin,
129→      });
130→    }
131→
132→    // Sort by occurrence count (most frequent first)
133→    suggestions.sort((a, b) => b.occurrences - a.occurrences);
134→
135→    return NextResponse.json(suggestions.slice(0, 10));
136→  } catch {
137→    return unauthorizedResponse();
138→  }
139→}
