 8→) {
 9→  try {
10→    const userId = await getAuthenticatedUserId();
11→
12→    const { id } = await params;
13→    const body = await request.json();
14→    const { month, year, amount } = body;
15→
16→    if (!month || !year) {
17→      return NextResponse.json(
18→        { error: "Mes e ano sao obrigatorios" },
19→        { status: 400 }
20→      );
21→    }
22→
23→    const recurringExpense = await prisma.recurringExpense.findUnique({
24→      where: { id, userId },
25→    });
26→
27→    if (!recurringExpense) {
28→      return NextResponse.json(
29→        { error: "Despesa recorrente nao encontrada" },
30→        { status: 404 }
31→      );
32→    }
33→
34→    // Check if this recurring expense should be auto-generated
35→    if (!recurringExpense.autoGenerate) {
36→      return NextResponse.json(
37→        { error: "Esta despesa aguarda vinculacao via importacao de fatura. Desative 'Gerar automaticamente' se quiser gerar manualmente." },
38→        { status: 400 }
39→      );
40→    }
41→
42→    // Check if transaction already exists for this month
43→    const startOfMonth = new Date(year, month - 1, 1);
44→    const endOfMonth = new Date(year, month, 0);
45→
46→    const existingTransaction = await prisma.transaction.findFirst({
47→      where: {
48→        recurringExpenseId: id,
49→        userId,
50→        date: {
51→          gte: startOfMonth,
52→          lte: endOfMonth,
53→        },
54→      },
55→    });
56→
57→    if (existingTransaction) {
58→      return NextResponse.json(
59→        { error: "Ja existe uma transacao para este mes", transaction: existingTransaction },
60→        { status: 400 }
61→      );
62→    }
63→
64→    // Calculate the date (use dayOfMonth, but cap at last day of month)
65→    const lastDayOfMonth = new Date(year, month, 0).getDate();
66→    const day = Math.min(recurringExpense.dayOfMonth, lastDayOfMonth);
67→    const transactionDate = new Date(year, month - 1, day);
68→
69→    // Use custom amount or default amount
70→    const finalAmount = amount !== undefined ? Math.abs(amount) : recurringExpense.defaultAmount;
71→
72→    const transaction = await prisma.transaction.create({
73→      data: {
74→        description: recurringExpense.description,
75→        amount: recurringExpense.type === "EXPENSE" ? -finalAmount : finalAmount,
76→        date: transactionDate,
77→        type: recurringExpense.type,
78→        origin: recurringExpense.origin,
79→        categoryId: recurringExpense.categoryId,
80→        isFixed: true,
81→        recurringExpenseId: id,
82→        userId,
83→      },
84→      include: {
85→        category: true,
86→        recurringExpense: true,
87→      },
