  4→
  5→interface TransactionToCheck {
  6→  description: string;
  7→  amount: number;
  8→  date: string;
  9→  origin?: string;
 10→}
 11→
 12→interface RecurringMatch {
 13→  index: number;
 14→  recurringExpenseId: string;
 15→  recurringDescription: string;
 16→  recurringAmount: number;
 17→  hasExistingTransaction: boolean;
 18→}
 19→
 20→function normalizeText(text: string): string {
 21→  return text
 22→    .toLowerCase()
 23→    .normalize("NFD")
 24→    .replace(/[\u0300-\u036f]/g, "")
 25→    .trim();
 26→}
 27→
 28→function matchesRecurring(
 29→  transactionDesc: string,
 30→  recurringDesc: string
 31→): boolean {
 32→  const normalizedTransaction = normalizeText(transactionDesc);
 33→  const normalizedRecurring = normalizeText(recurringDesc);
 34→
 35→  const keywords = normalizedRecurring.split(/\s+/).filter((k) => k.length > 2);
 36→  return keywords.some((keyword) => normalizedTransaction.includes(keyword));
 37→}
 38→
 39→export async function POST(request: NextRequest) {
 40→  try {
 41→    const userId = await getAuthenticatedUserId();
 42→    const body = await request.json();
 43→    const { transactions, origin } = body as {
 44→      transactions: TransactionToCheck[];
 45→      origin?: string;
 46→    };
 47→
 48→    if (!transactions || !Array.isArray(transactions)) {
 49→      return NextResponse.json(
 50→        { error: "Transacoes nao fornecidas" },
 51→        { status: 400 }
 52→      );
 53→    }
 54→
 55→    // Fetch all active recurring expenses
 56→    const recurringExpenses = await prisma.recurringExpense.findMany({
 57→      where: {
 58→        userId,
 59→        isActive: true,
 60→      },
 61→      include: {
 62→        transactions: {
 63→          select: { id: true, date: true },
 64→          where: { deletedAt: null },
 65→        },
 66→      },
 67→    });
 68→
 69→    const matches: RecurringMatch[] = [];
 70→
 71→    for (let i = 0; i < transactions.length; i++) {
 72→      const t = transactions[i];
 73→      const dateStr = !t.date.includes("T") ? t.date + "T12:00:00" : t.date;
 74→      const transactionDate = new Date(dateStr);
 75→      const transactionMonth = transactionDate.getMonth();
 76→      const transactionYear = transactionDate.getFullYear();
 77→      const transactionOrigin = origin || t.origin || "";
 78→
 79→      const matchingRecurring = recurringExpenses.filter((recurring) => {
 80→        // Origin must match if both sides have a non-empty value
 81→        if (transactionOrigin && recurring.origin && recurring.origin !== transactionOrigin) {
 82→          return false;
 83→        }
 84→
 85→        // Description must match
 86→        if (!matchesRecurring(t.description, recurring.description)) {
 87→          return false;
 88→        }
 89→
 90→        return true;
 91→      });
 92→
 93→      // Only use if exactly one match (conservative)
 94→      if (matchingRecurring.length === 1) {
 95→        const recurring = matchingRecurring[0];
 96→
 97→        // Check if recurring already has a transaction for this month
 98→        const hasExistingTransaction = recurring.transactions.some((tx) => {
 99→          const txDate = new Date(tx.date);
100→          return (
101→            txDate.getMonth() === transactionMonth &&
102→            txDate.getFullYear() === transactionYear
103→          );
104→        });
105→
106→        matches.push({
107→          index: i,
108→          recurringExpenseId: recurring.id,
109→          recurringDescription: recurring.description,
110→          recurringAmount: recurring.defaultAmount,
111→          hasExistingTransaction,
112→        });
113→      }
114→    }
115→
116→    return NextResponse.json({
117→      matches,
118→      hasMatches: matches.length > 0,
119→    });
120→  } catch (error) {
121→    if (error instanceof Error && error.message === "Unauthorized") {
122→      return unauthorizedResponse();
123→    }
124→    console.error("Error checking recurring matches:", error);
125→    return NextResponse.json(
126→      { error: "Erro ao verificar recorrentes" },
127→      { status: 500 }
128→    );
129→  }
130→}
