  4→
  5→export async function GET(request: NextRequest) {
  6→  try {
  7→    const userId = await getAuthenticatedUserId();
  8→
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const month = searchParams.get("month");
 11→    const year = searchParams.get("year");
 12→    const thresholdParam = searchParams.get("threshold");
 13→
 14→    const currentDate = new Date();
 15→    const targetMonth = month ? parseInt(month) : currentDate.getMonth() + 1;
 16→    const targetYear = year ? parseInt(year) : currentDate.getFullYear();
 17→    const threshold = thresholdParam ? parseFloat(thresholdParam) : 2; // Default: 2x average
 18→
 19→    // Get transactions for target month
 20→    const startDate = new Date(targetYear, targetMonth - 1, 1);
 21→    const endDate = new Date(targetYear, targetMonth, 0);
 22→
 23→    const currentMonthTransactions = await prisma.transaction.findMany({
 24→      where: {
 25→        userId,
 26→        date: {
 27→          gte: startDate,
 28→          lte: endDate,
 29→        },
 30→        type: "EXPENSE",
 31→        deletedAt: null,
 32→        investmentTransaction: null,
 33→      },
 34→      include: {
 35→        category: true,
 36→      },
 37→    });
 38→
 39→    // Get transactions from last 6 months for average calculation
 40→    const sixMonthsAgo = new Date(targetYear, targetMonth - 7, 1);
 41→    const lastMonthEnd = new Date(targetYear, targetMonth - 1, 0);
 42→
 43→    const historicalTransactions = await prisma.transaction.findMany({
 44→      where: {
 45→        userId,
 46→        date: {
 47→          gte: sixMonthsAgo,
 48→          lte: lastMonthEnd,
 49→        },
 50→        type: "EXPENSE",
 51→        deletedAt: null,
 52→        investmentTransaction: null,
 53→      },
 54→      include: {
 55→        category: true,
 56→      },
 57→    });
 58→
 59→    // Calculate average per category from historical data
 60→    // Track both total amount and which months had transactions
 61→    const categoryAverages: Record<string, {
 62→      total: number;
 63→      count: number;
 64→      months: Set<string>;
 65→      name: string;
 66→      color: string
 67→    }> = {};
 68→
 69→    for (const t of historicalTransactions) {
 70→      if (t.categoryId) {
 71→        if (!categoryAverages[t.categoryId]) {
 72→          categoryAverages[t.categoryId] = {
 73→            total: 0,
 74→            count: 0,
 75→            months: new Set(),
 76→            name: t.category?.name || "Sem categoria",
 77→            color: t.category?.color || "#888888",
 78→          };
 79→        }
 80→        categoryAverages[t.categoryId].total += Math.abs(t.amount);
 81→        categoryAverages[t.categoryId].count += 1;
 82→        // Track which month this transaction belongs to
 83→        const txDate = new Date(t.date);
 84→        const monthKey = `${txDate.getFullYear()}-${txDate.getMonth()}`;
 85→        categoryAverages[t.categoryId].months.add(monthKey);
 86→      }
 87→    }
 88→
 89→    // Calculate average transaction amount per category
 90→    const categoryAvgAmounts: Record<string, number> = {};
 91→    for (const [categoryId, data] of Object.entries(categoryAverages)) {
 92→      categoryAvgAmounts[categoryId] = data.count > 0 ? data.total / data.count : 0;
 93→    }
 94→
 95→    // Find unusual transactions (amount > threshold * category average)
 96→    // Only consider categories with history in at least 2 different months
 97→    const MIN_MONTHS_FOR_HISTORY = 2;
 98→
 99→    const unusualTransactions = currentMonthTransactions
100→      .filter(t => {
101→        if (!t.categoryId) return false;
102→        const categoryData = categoryAverages[t.categoryId];
103→        // Skip if category doesn't have enough historical data
104→        if (!categoryData || categoryData.months.size < MIN_MONTHS_FOR_HISTORY) return false;
105→        const avgAmount = categoryAvgAmounts[t.categoryId];
106→        if (!avgAmount || avgAmount === 0) return false;
107→        const amount = Math.abs(t.amount);
108→        return amount > threshold * avgAmount;
109→      })
110→      .map(t => {
111→        const avgAmount = categoryAvgAmounts[t.categoryId!] || 0;
112→        const amount = Math.abs(t.amount);
113→        const exceedsBy = avgAmount > 0 ? ((amount - avgAmount) / avgAmount) * 100 : 0;
114→
115→        return {
116→          id: t.id,
117→          description: t.description,
118→          amount: amount,
119→          date: t.date,
120→          categoryId: t.categoryId,
121→          categoryName: t.category?.name || null,
122→          categoryColor: t.category?.color || null,
123→          categoryAverage: avgAmount,
124→          exceedsBy,
125→        };
126→      })
127→      .sort((a, b) => b.exceedsBy - a.exceedsBy);
128→
129→    return NextResponse.json({
130→      transactions: unusualTransactions,
131→      threshold,
132→      period: {
133→        month: targetMonth,
134→        year: targetYear,
135→      },
136→    });
137→  } catch (error) {
138→    if (error instanceof Error && error.message === "Unauthorized") {
139→      return unauthorizedResponse();
140→    }
141→    console.error("Error fetching unusual transactions:", error);
142→    return NextResponse.json(
143→      { error: "Erro ao buscar transacoes incomuns" },
144→      { status: 500 }
145→    );
146→  }
147→}
