 1→import { NextRequest, NextResponse } from "next/server";
 2→import prisma from "@/lib/db";
 3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
 4→
 5→export async function POST(
 6→  request: NextRequest,
 7→  { params }: { params: Promise<{ id: string }> }
 8→) {
 9→  try {
10→    const userId = await getAuthenticatedUserId();
11→
12→    const { id } = await params;
13→    const body = await request.json();
14→    const { dayOfMonth, autoGenerate = true } = body;
15→
16→    // Fetch the transaction
17→    const transaction = await prisma.transaction.findUnique({
18→      where: { id, userId },
19→      include: { category: true },
20→    });
21→
22→    if (!transaction) {
23→      return NextResponse.json(
24→        { error: "Transacao nao encontrada" },
25→        { status: 404 }
26→      );
27→    }
28→
29→    // Check if transaction is already linked to a recurring expense
30→    if (transaction.recurringExpenseId) {
31→      return NextResponse.json(
32→        { error: "Esta transacao ja esta vinculada a uma despesa recorrente" },
33→        { status: 400 }
34→      );
35→    }
36→
37→    // Check if transaction is an installment
38→    if (transaction.isInstallment || transaction.installmentId) {
39→      return NextResponse.json(
40→        { error: "Transacoes parceladas nao podem ser marcadas como recorrentes" },
41→        { status: 400 }
42→      );
43→    }
44→
45→    // Calculate day of month from transaction date if not provided
46→    const transactionDate = new Date(transaction.date);
47→    const calculatedDayOfMonth = dayOfMonth || transactionDate.getDate();
48→
49→    // Create the recurring expense and link the transaction in a single transaction
50→    const result = await prisma.$transaction(async (tx) => {
51→      // Create the recurring expense
52→      const recurringExpense = await tx.recurringExpense.create({
53→        data: {
54→          description: transaction.description,
55→          defaultAmount: Math.abs(transaction.amount),
56→          dayOfMonth: calculatedDayOfMonth,
57→          type: transaction.type,
58→          origin: transaction.origin,
59→          categoryId: transaction.categoryId,
60→          isActive: true,
61→          autoGenerate,
62→          userId,
63→        },
64→      });
65→
66→      // Update the transaction to link it to the recurring expense and mark as fixed
67→      const updatedTransaction = await tx.transaction.update({
68→        where: { id, userId },
69→        data: {
70→          recurringExpenseId: recurringExpense.id,
71→          isFixed: true,
72→        },
73→        include: {
74→          category: true,
75→          recurringExpense: true,
76→        },
77→      });
78→
79→      return { recurringExpense, transaction: updatedTransaction };
80→    });
81→
82→    return NextResponse.json(result);
83→  } catch (error) {
84→    if (error instanceof Error && error.message === "Unauthorized") {
85→      return unauthorizedResponse();
86→    }
87→    console.error("Error making transaction recurring:", error);
88→    return NextResponse.json(
89→      { error: "Erro ao criar despesa recorrente" },
90→      { status: 500 }
91→    );
92→  }
93→}
