  5→interface BillPeriod {
  6→  label: string;
  7→  month: number;
  8→  year: number;
  9→  startDate: Date;
 10→  endDate: Date;
 11→  dueDate: Date;
 12→}
 13→
 14→interface CarryoverInfo {
 15→  amount: number;
 16→  interest: number;
 17→  fromBill: string;
 18→  billPaymentId: string;
 19→}
 20→
 21→// Calculate bill periods based on closing day
 22→function getBillPeriods(closingDay: number, count: number = 6): BillPeriod[] {
 23→  const periods: BillPeriod[] = [];
 24→  const today = new Date();
 25→
 26→  for (let i = 0; i < count; i++) {
 27→    // Calculate the reference month (current month - i)
 28→    const refDate = new Date(today.getFullYear(), today.getMonth() - i, 1);
 29→    const refMonth = refDate.getMonth();
 30→    const refYear = refDate.getFullYear();
 31→
 32→    // Bill period: from (closingDay + 1) of previous month to closingDay of current month
 33→    const startDate = new Date(refYear, refMonth - 1, closingDay + 1);
 34→    const endDate = new Date(refYear, refMonth, closingDay, 23, 59, 59, 999);
 35→
 36→    // Due date is typically 7-10 days after closing (using 7 days as default)
 37→    const dueDate = new Date(refYear, refMonth, closingDay + 7);
 38→
 39→    // Label: month/year of the due date
 40→    const monthNames = [
 41→      "Janeiro", "Fevereiro", "Marco", "Abril", "Maio", "Junho",
 42→      "Julho", "Agosto", "Setembro", "Outubro", "Novembro", "Dezembro"
 43→    ];
 44→    const label = `${monthNames[refMonth]} ${refYear}`;
 45→
 46→    periods.push({
 47→      label,
 48→      month: refMonth + 1, // 1-12 format
 49→      year: refYear,
 50→      startDate,
 51→      endDate,
 52→      dueDate,
 53→    });
 54→  }
 55→
 56→  return periods;
 57→}
