 41→export async function PUT(
 42→  request: NextRequest,
 43→  { params }: { params: Promise<{ id: string }> }
 44→) {
 45→  try {
 46→    const userId = await getAuthenticatedUserId();
 47→    const { id } = await params;
 48→    const body = await request.json();
 49→    const {
 50→      interestRate,
 51→      amountPaid,
 52→      paymentType,
 53→      installments,
 54→    } = body;
 55→
 56→    // Verify bill payment belongs to user before updating
 57→    const existingBillPayment = await prisma.billPayment.findFirst({
 58→      where: { id, userId },
 59→    });
 60→
 61→    if (!existingBillPayment) {
 62→      return NextResponse.json(
 63→        { error: "Pagamento de fatura nao encontrado" },
 64→        { status: 404 }
 65→      );
 66→    }
 67→
 68→    // Build update data based on provided fields
 69→    const updateData: Record<string, unknown> = {};
 70→
 71→    // Update interestRate if provided
 72→    if (interestRate !== undefined) {
 73→      updateData.interestRate = interestRate;
 74→      // Recalculate interest amount based on new rate
 75→      updateData.interestAmount = interestRate
 76→        ? (existingBillPayment.amountCarried * interestRate) / 100
 77→        : null;
 78→    }
 79→
 80→    // Update amountPaid if provided (will recalculate amountCarried)
 81→    if (amountPaid !== undefined) {
 82→      // Validate amountPaid is less than totalBillAmount
 83→      if (amountPaid >= existingBillPayment.totalBillAmount) {
 84→        return NextResponse.json(
 85→          { error: "amountPaid deve ser menor que totalBillAmount para pagamento parcial" },
 86→          { status: 400 }
 87→        );
 88→      }
 89→
 90→      updateData.amountPaid = amountPaid;
 91→      updateData.amountCarried = existingBillPayment.totalBillAmount - amountPaid;
 92→
 93→      // Recalculate interest amount if there's an interest rate
 94→      const currentInterestRate = interestRate !== undefined
 95→        ? interestRate
 96→        : existingBillPayment.interestRate;
 97→      if (currentInterestRate) {
 98→        updateData.interestAmount = ((updateData.amountCarried as number) * currentInterestRate) / 100;
 99→      }
100→    }
101→
102→    // Update paymentType if provided
103→    if (paymentType !== undefined) {
104→      const validPaymentTypes: BillPaymentType[] = ["PARTIAL", "FINANCED"];
105→      if (!validPaymentTypes.includes(paymentType)) {
106→        return NextResponse.json(
107→          { error: "paymentType deve ser 'PARTIAL' ou 'FINANCED'" },
108→          { status: 400 }
109→        );
110→      }
111→
112→      // Validate installments for FINANCED type
113→      if (paymentType === "FINANCED" && (!installments || installments < 2)) {
114→        return NextResponse.json(
115→          { error: "Para parcelamento, o numero de parcelas deve ser pelo menos 2" },
116→          { status: 400 }
117→        );
118→      }
119→
120→      updateData.paymentType = paymentType;
121→    }
122→
123→    // If no fields to update, return error
124→    if (Object.keys(updateData).length === 0) {
125→      return NextResponse.json(
126→        { error: "Nenhum campo valido para atualizar" },
127→        { status: 400 }
128→      );
129→    }
130→
131→    const billPayment = await prisma.billPayment.update({
132→      where: { id },
133→      data: updateData,
134→      include: {
135→        installment: true,
136→      },
137→    });
138→
139→    return NextResponse.json(billPayment);
140→  } catch (error) {
141→    if (error instanceof Error && error.message === "Unauthorized") {
142→      return unauthorizedResponse();
143→    }
144→    console.error("Error updating bill payment:", error);
145→    return NextResponse.json(
146→      { error: "Erro ao atualizar pagamento de fatura" },
147→      { status: 500 }
148→    );
149→  }
150→}
151→
152→export async function DELETE(
153→  request: NextRequest,
154→  { params }: { params: Promise<{ id: string }> }
155→) {
156→  try {
157→    const userId = await getAuthenticatedUserId();
158→    const { id } = await params;
159→
160→    // Verify bill payment belongs to user before deleting
161→    const existingBillPayment = await prisma.billPayment.findFirst({
162→      where: { id, userId },
163→      include: {
164→        installment: {
165→          include: {
166→            transactions: true,
167→          },
168→        },
169→      },
170→    });
171→
172→    if (!existingBillPayment) {
173→      return NextResponse.json(
174→        { error: "Pagamento de fatura nao encontrado" },
175→        { status: 404 }
176→      );
177→    }
178→
179→    // Use transaction for atomic cleanup
180→    await prisma.$transaction(async (tx) => {
181→      // Cleanup generated transactions (soft delete)
182→      // Entry transaction
183→      if (existingBillPayment.entryTransactionId) {
184→        await tx.transaction.update({
185→          where: { id: existingBillPayment.entryTransactionId },
186→          data: { deletedAt: new Date() },
187→        });
188→      }
189→
190→      // Carryover transaction
191→      if (existingBillPayment.carryoverTransactionId) {
192→        await tx.transaction.update({
193→          where: { id: existingBillPayment.carryoverTransactionId },
194→          data: { deletedAt: new Date() },
195→        });
196→      }
197→
198→      // If there's an installment, soft delete related transactions
199→      if (existingBillPayment.installment) {
200→        for (const transaction of existingBillPayment.installment.transactions) {
201→          await tx.transaction.update({
202→            where: { id: transaction.id },
203→            data: { deletedAt: new Date() },
204→          });
205→        }
206→
207→        // Delete the installment record
208→        await tx.installment.delete({
209→          where: { id: existingBillPayment.installment.id },
210→        });
211→      }
212→
213→      // Delete the bill payment
214→      await tx.billPayment.delete({
215→        where: { id },
216→      });
217→    });
218→
219→    return NextResponse.json({ success: true });
220→  } catch (error) {
221→    if (error instanceof Error && error.message === "Unauthorized") {
222→      return unauthorizedResponse();
223→    }
224→    console.error("Error deleting bill payment:", error);
225→    return NextResponse.json(
226→      { error: "Erro ao excluir pagamento de fatura" },
227→      { status: 500 }
228→    );
229→  }
230→}
