  1→import { NextRequest, NextResponse } from "next/server";
  2→import { processFile } from "@/lib/ocr-parser";
  3→import { parseStatementText, suggestCategoryForStatement } from "@/lib/statement-parser";
  4→import { suggestCategory, detectInstallment, detectRecurringTransaction } from "@/lib/categorizer";
  5→import prisma from "@/lib/db";
  6→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  7→import type { ImportedTransaction } from "@/types";
  8→
  9→export const runtime = "nodejs";
 10→export const maxDuration = 60; // Allow up to 60 seconds for OCR processing
 11→
 12→export async function POST(request: NextRequest) {
 13→  try {
 14→    const userId = await getAuthenticatedUserId();
 15→    const formData = await request.formData();
 16→    const file = formData.get("file") as File | null;
 17→
 18→    if (!file) {
 19→      return NextResponse.json(
 20→        { error: "Nenhum arquivo enviado" },
 21→        { status: 400 }
 22→      );
 23→    }
 24→
 25→    // Validate file type
 26→    const fileName = file.name.toLowerCase();
 27→    const validExtensions = [".pdf", ".png", ".jpg", ".jpeg", ".gif", ".webp"];
 28→    const isValid = validExtensions.some((ext) => fileName.endsWith(ext));
 29→
 30→    if (!isValid) {
 31→      return NextResponse.json(
 32→        { error: "Formato de arquivo nao suportado. Use PDF ou imagem (PNG, JPG)" },
 33→        { status: 400 }
 34→      );
 35→    }
 36→
 37→    // Process file with OCR
 38→    const ocrResult = await processFile(file);
 39→
 40→    if (!ocrResult.text || ocrResult.text.trim().length === 0) {
 41→      return NextResponse.json(
 42→        { error: "Nao foi possivel extrair texto do arquivo. Verifique se a imagem esta legivel." },
 43→        { status: 400 }
 44→      );
 45→    }
 46→
 47→    // Parse statement text
 48→    const parseResult = parseStatementText(ocrResult.text, ocrResult.confidence);
 49→
 50→    if (parseResult.transactions.length === 0) {
 51→      return NextResponse.json(
 52→        {
 53→          error: "Nenhuma transacao encontrada no arquivo. Certifique-se de que o extrato esta claro e legivel.",
 54→          rawText: ocrResult.text,
 55→          confidence: ocrResult.confidence,
 56→        },
 57→        { status: 400 }
 58→      );
 59→    }
 60→
 61→    // Convert to ImportedTransaction format and apply categorization
 62→    const transactions: (ImportedTransaction & {
 63→      categoryId?: string;
 64→      selected: boolean;
 65→      transactionKind?: string;
 66→    })[] = [];
 67→
 68→    // Get default category "Outros" for when no rule matches
 69→    const defaultCategory = await prisma.category.findFirst({
 70→      where: { userId, name: "Outros" },
 71→    });
 72→
 73→    for (const t of parseResult.transactions) {
 74→      // Try to find category from rules
 75→      const suggestedCat = await suggestCategory(t.description, userId);
 76→
 77→      // If no rule matched, use default category "Outros"
 78→      let categoryId = suggestedCat?.id || defaultCategory?.id;
 79→
 80→      // Detect installments
 81→      const installmentInfo = detectInstallment(t.description);
 82→
 83→      // Detect recurring transactions (subscriptions)
 84→      const recurringInfo = detectRecurringTransaction(t.description);
 85→
 86→      transactions.push({
 87→        description: t.description,
 88→        amount: t.amount,
 89→        date: t.date,
 90→        type: t.type,
 91→        categoryId,
 92→        suggestedCategoryId: categoryId,
 93→        isInstallment: installmentInfo.isInstallment,
 94→        currentInstallment: installmentInfo.currentInstallment,
 95→        totalInstallments: installmentInfo.totalInstallments,
 96→        isRecurring: recurringInfo.isRecurring,
 97→        recurringName: recurringInfo.recurringName,
 98→        confidence: t.confidence,
 99→        transactionKind: t.transactionKind,
100→        selected: true,
101→      });
102→    }
103→
104→    return NextResponse.json({
105→      transactions,
106→      origin: parseResult.bank,
107→      confidence: parseResult.averageConfidence,
108→      rawText: ocrResult.text,
109→    });
110→  } catch (error) {
111→    if (error instanceof Error && error.message === "Unauthorized") {
112→      return unauthorizedResponse();
113→    }
114→    console.error("OCR processing error:", error);
115→    return NextResponse.json(
116→      {
117→        error: error instanceof Error ? error.message : "Erro ao processar arquivo",
118→      },
119→      { status: 500 }
120→    );
121→  }
122→}
