22→    const updateData: Record<string, unknown> = {};
23→    if (body.isActive !== undefined) updateData.isActive = body.isActive;
24→    if (body.description !== undefined) updateData.description = body.description;
25→    if (body.totalAmount !== undefined) {
26→      const parsedAmount = parseFloat(body.totalAmount);
27→      if (isNaN(parsedAmount) || parsedAmount <= 0) {
28→        return NextResponse.json({ error: "Valor deve ser um número positivo" }, { status: 400 });
29→      }
30→      updateData.totalAmount = parsedAmount;
31→    }
32→    if (body.totalInstallments !== undefined) {
