34→      if (isNaN(parsedInstallments) || parsedInstallments < 1) {
35→        return NextResponse.json({ error: "Parcelas deve ser um número positivo" }, { status: 400 });
36→      }
37→      updateData.totalInstallments = parsedInstallments;
38→    }
39→    if (body.categoryId !== undefined) updateData.categoryId = body.categoryId || null;
