  1→import { NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→const MONTH_LABELS = [
  6→  "jan", "fev", "mar", "abr", "mai", "jun",
  7→  "jul", "ago", "set", "out", "nov", "dez",
  8→];
  9→
 10→export async function GET() {
 11→  try {
 12→    const userId = await getAuthenticatedUserId();
 13→    const now = new Date();
 14→
 15→    // 1. Average income from last 3 months (only months with income)
 16→    const threeMonthsAgo = new Date(now.getFullYear(), now.getMonth() - 3, 1);
 17→    const currentMonthEnd = new Date(now.getFullYear(), now.getMonth() + 1, 0);
 18→
 19→    const incomeTransactions = await prisma.transaction.findMany({
 20→      where: {
 21→        userId,
 22→        type: "INCOME",
 23→        date: { gte: threeMonthsAgo, lte: currentMonthEnd },
 24→        deletedAt: null,
 25→        investmentTransaction: null,
 26→      },
 27→    });
 28→
 29→    const incomeByMonth = new Map<string, number>();
 30→    for (const t of incomeTransactions) {
 31→      const d = new Date(t.date);
 32→      const key = `${d.getFullYear()}-${d.getMonth()}`;
 33→      incomeByMonth.set(key, (incomeByMonth.get(key) || 0) + Math.abs(t.amount));
 34→    }
 35→    const monthlyIncomes = Array.from(incomeByMonth.values());
 36→    const averageIncome =
 37→      monthlyIncomes.length > 0
 38→        ? monthlyIncomes.reduce((sum, v) => sum + v, 0) / monthlyIncomes.length
 39→        : 0;
 40→
 41→    // 2. Active recurring expenses with effective amounts
 42→    const activeRecurring = await prisma.recurringExpense.findMany({
 43→      where: { userId, isActive: true },
 44→    });
 45→
 46→    const recurringWithLatestAmount = await Promise.all(
 47→      activeRecurring.map(async (recurring) => {
 48→        const latestTransaction = await prisma.transaction.findFirst({
 49→          where: { userId, recurringExpenseId: recurring.id },
 50→          orderBy: { date: "desc" },
 51→          select: { amount: true },
 52→        });
 53→        return {
 54→          ...recurring,
 55→          effectiveAmount: latestTransaction?.amount ?? recurring.defaultAmount,
 56→        };
 57→      })
 58→    );
 59→
 60→    // 3. Future installments (next 12 months) - grouped
 61→    const startOfCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
 62→    const endDate = new Date(now.getFullYear(), now.getMonth() + 12, 0);
 63→
 64→    const futureInstallments = await prisma.transaction.findMany({
 65→      where: {
 66→        userId,
 67→        isInstallment: true,
 68→        installmentId: { not: null },
 69→        date: { gte: startOfCurrentMonth, lte: endDate },
 70→        deletedAt: null,
 71→      },
 72→    });
 73→
 74→    // 3b. Standalone installments (manually tagged, no group) - project remaining
 75→    const standaloneInstallments = await prisma.transaction.findMany({
 76→      where: {
 77→        userId,
 78→        isInstallment: true,
 79→        installmentId: null,
 80→        totalInstallments: { not: null },
 81→        currentInstallment: { not: null },
 82→        deletedAt: null,
 83→      },
 84→    });
 85→
 86→    const projectedStandalone: Array<{ amount: number; date: Date }> = [];
 87→    standaloneInstallments.forEach((t) => {
 88→      if (!t.currentInstallment || !t.totalInstallments) return;
 89→      const remaining = t.totalInstallments - t.currentInstallment;
 90→      const tDate = new Date(t.date);
 91→      for (let j = 1; j <= remaining; j++) {
 92→        const futureDate = new Date(tDate);
 93→        futureDate.setMonth(tDate.getMonth() + j);
 94→        if (futureDate >= startOfCurrentMonth && futureDate <= endDate) {
 95→          projectedStandalone.push({ amount: Math.abs(t.amount), date: futureDate });
 96→        }
 97→      }
 98→    });
 99→
100→    // 4. Build 12-month baseline
101→    const months = [];
102→    for (let i = 0; i < 12; i++) {
103→      const projMonth = now.getMonth() + i;
104→      const projYear = now.getFullYear() + Math.floor(projMonth / 12);
105→      const normalizedMonth = (projMonth % 12) + 1;
106→      const label = `${MONTH_LABELS[normalizedMonth - 1]}/${String(projYear).slice(-2)}`;
107→
108→      const monthInstallments = futureInstallments.filter((t) => {
109→        const d = new Date(t.date);
110→        return d.getMonth() + 1 === normalizedMonth && d.getFullYear() === projYear;
111→      });
112→      const monthStandalone = projectedStandalone.filter((t) => {
113→        return t.date.getMonth() + 1 === normalizedMonth && t.date.getFullYear() === projYear;
114→      });
115→      const installmentsTotal =
116→        monthInstallments.reduce((sum, t) => sum + Math.abs(t.amount), 0) +
117→        monthStandalone.reduce((sum, t) => sum + t.amount, 0);
118→
119→      const recurringExpensesTotal = recurringWithLatestAmount
120→        .filter((r) => r.type === "EXPENSE")
121→        .reduce((sum, r) => sum + Math.abs(r.effectiveAmount), 0);
122→
123→      months.push({
124→        month: normalizedMonth,
125→        year: projYear,
126→        label,
127→        currentExpenses: recurringExpensesTotal + installmentsTotal,
128→        recurringExpenses: recurringExpensesTotal,
129→        installmentsTotal,
130→      });
131→    }
132→
133→    return NextResponse.json({ averageIncome, months });
134→  } catch (error) {
135→    if (error instanceof Error && error.message === "Unauthorized") {
136→      return unauthorizedResponse();
137→    }
138→    console.error("Error fetching simulation data:", error);
139→    return NextResponse.json(
140→      { error: "Erro ao buscar dados de simulação" },
141→      { status: 500 }
142→    );
143→  }
144→}
