 68→export async function POST(request: NextRequest) {
 69→  try {
 70→    const userId = await getAuthenticatedUserId();
 71→    const body = await request.json();
 72→    const {
 73→      name,
 74→      categoryId,
 75→      initialValue,
 76→      description,
 77→      goalAmount,
 78→      broker,
 79→      date,
 80→    } = body;
 81→
 82→    // Validate required fields
 83→    if (!name || !categoryId || initialValue === undefined) {
 84→      return NextResponse.json(
 85→        { error: "Campos obrigatorios: name, categoryId, initialValue" },
 86→        { status: 400 }
 87→      );
 88→    }
 89→
 90→    const investmentDate = date ? new Date(date + "T12:00:00") : new Date();
 91→    const amount = Math.abs(initialValue);
 92→
 93→    // Use a transaction for atomicity
 94→    const result = await prisma.$transaction(async (tx) => {
 95→      // 1. Create the Investment record
 96→      const investment = await tx.investment.create({
 97→        data: {
 98→          name,
 99→          description: description || null,
100→          categoryId,
101→          currentValue: amount,
102→          totalInvested: amount,
103→          totalWithdrawn: 0,
104→          goalAmount: goalAmount || null,
105→          broker: broker || null,
106→          userId,
107→        },
108→        include: {
109→          category: true,
110→        },
111→      });
112→
113→      // 2. Find the "Investimentos" category for transactions
114→      // First try user's own category, then fall back to global default
115→      let transactionCategory = await tx.category.findFirst({
116→        where: {
117→          name: "Investimentos",
118→          userId,
119→        },
120→      });
121→
122→      if (!transactionCategory) {
123→        transactionCategory = await tx.category.findFirst({
124→          where: {
125→            name: "Investimentos",
126→            userId: null,
127→          },
128→        });
129→      }
130→
131→      // 3. Create a Transaction (type: EXPENSE) for the initial deposit
132→      const transaction = await tx.transaction.create({
133→        data: {
134→          description: `Aporte - ${name}`,
135→          amount: -amount, // Negative for expense
136→          date: investmentDate,
137→          type: "EXPENSE",
138→          origin: broker || "Investimento",
139→          categoryId: transactionCategory?.id || null,
140→          isFixed: false,
141→          isInstallment: false,
142→          userId,
143→        },
144→      });
145→
146→      // 4. Create an InvestmentTransaction (type: DEPOSIT) linked to that transaction
147→      await tx.investmentTransaction.create({
148→        data: {
149→          investmentId: investment.id,
150→          type: "DEPOSIT",
151→          amount: amount,
152→          date: investmentDate,
153→          linkedTransactionId: transaction.id,
154→        },
155→      });
156→
157→      return investment;
158→    });
159→
160→    // Calculate fields for response
161→    const totalReturn = result.currentValue - result.totalInvested + result.totalWithdrawn;
162→    const totalReturnPercent = result.totalInvested > 0
163→      ? (totalReturn / result.totalInvested) * 100
164→      : 0;
165→    const goalProgress = result.goalAmount && result.goalAmount > 0
166→      ? (result.currentValue / result.goalAmount) * 100
167→      : null;
168→
169→    return NextResponse.json(
170→      {
171→        ...result,
172→        totalReturn,
173→        totalReturnPercent,
174→        goalProgress,
175→      },
176→      { status: 201 }
177→    );
178→  } catch (error) {
179→    if (error instanceof Error && error.message === "Unauthorized") {
180→      return unauthorizedResponse();
181→    }
182→    console.error("Error creating investment:", error);
183→    return NextResponse.json(
184→      { error: "Erro ao criar investimento" },
185→      { status: 500 }
186→    );
187→  }
188→}
