  1→import { NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→interface CategorySummary {
  6→  id: string;
  7→  name: string;
  8→  color: string;
  9→  value: number;
 10→  percent: number;
 11→}
 12→
 13→interface GoalProgress {
 14→  investmentId: string;
 15→  name: string;
 16→  current: number;
 17→  goal: number;
 18→  percent: number;
 19→}
 20→
 21→interface InvestmentSummaryResponse {
 22→  totalValue: number;
 23→  totalInvested: number;
 24→  totalWithdrawn: number;
 25→  totalReturn: number;
 26→  totalReturnPercent: number;
 27→  byCategory: CategorySummary[];
 28→  goalsProgress: GoalProgress[];
 29→  investmentCount: number;
 30→}
 31→
 32→export async function GET(): Promise<NextResponse<InvestmentSummaryResponse | { error: string }>> {
 33→  try {
 34→    const userId = await getAuthenticatedUserId();
 35→
 36→    // Fetch all investments for the user
 37→    const investments = await prisma.investment.findMany({
 38→      where: {
 39→        userId,
 40→      },
 41→      include: {
 42→        category: true,
 43→      },
 44→    });
 45→
 46→    // Calculate totals
 47→    let totalValue = 0;
 48→    let totalInvested = 0;
 49→    let totalWithdrawn = 0;
 50→
 51→    // Group by category
 52→    const categoryMap = new Map<string, { name: string; color: string; value: number }>();
 53→
 54→    // Track goals
 55→    const goalsProgress: GoalProgress[] = [];
 56→
 57→    for (const investment of investments) {
 58→      totalValue += investment.currentValue;
 59→      totalInvested += investment.totalInvested;
 60→      totalWithdrawn += investment.totalWithdrawn;
 61→
 62→      // Add to category map
 63→      const categoryId = investment.categoryId;
 64→      const existing = categoryMap.get(categoryId);
 65→      if (existing) {
 66→        existing.value += investment.currentValue;
 67→      } else {
 68→        categoryMap.set(categoryId, {
 69→          name: investment.category.name,
 70→          color: investment.category.color,
 71→          value: investment.currentValue,
 72→        });
 73→      }
 74→
 75→      // Track goal progress for investments with goals
 76→      if (investment.goalAmount && investment.goalAmount > 0) {
 77→        const percent = (investment.currentValue / investment.goalAmount) * 100;
 78→        goalsProgress.push({
 79→          investmentId: investment.id,
 80→          name: investment.name,
 81→          current: investment.currentValue,
 82→          goal: investment.goalAmount,
 83→          percent,
 84→        });
 85→      }
 86→    }
 87→
 88→    // Calculate total return
 89→    const totalReturn = totalValue - totalInvested + totalWithdrawn;
 90→    const totalReturnPercent = totalInvested > 0 ? (totalReturn / totalInvested) * 100 : 0;
 91→
 92→    // Convert category map to array with percentages
 93→    const byCategory: CategorySummary[] = Array.from(categoryMap.entries())
 94→      .map(([id, data]) => ({
 95→        id,
 96→        name: data.name,
 97→        color: data.color,
 98→        value: data.value,
 99→        percent: totalValue > 0 ? (data.value / totalValue) * 100 : 0,
100→      }))
101→      .sort((a, b) => b.value - a.value);
102→
103→    // Sort goals by progress percentage (ascending - show closest to goal first)
104→    goalsProgress.sort((a, b) => b.percent - a.percent);
105→
106→    return NextResponse.json({
107→      totalValue,
108→      totalInvested,
109→      totalWithdrawn,
110→      totalReturn,
111→      totalReturnPercent,
112→      byCategory,
113→      goalsProgress,
114→      investmentCount: investments.length,
115→    });
116→  } catch (error) {
117→    if (error instanceof Error && error.message === "Unauthorized") {
118→      return unauthorizedResponse();
119→    }
120→    console.error("Error fetching investment summary:", error);
121→    const errorMessage = error instanceof Error ? error.message : "Unknown error";
122→    return NextResponse.json(
123→      { error: "Erro ao buscar resumo de investimentos", details: errorMessage },
124→      { status: 500 }
125→    );
126→  }
127→}
