  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→
  5→interface SnapshotData {
  6→  month: number;
  7→  year: number;
  8→  totalValue: number;
  9→  totalInvested: number;
 10→  totalWithdrawn: number;
 11→}
 12→
 13→interface SnapshotsResponse {
 14→  snapshots: SnapshotData[];
 15→  current: SnapshotData;
 16→}
 17→
 18→/**
 19→ * Calculate current investment totals from all investments
 20→ */
 21→async function calculateCurrentTotals(userId: string): Promise<{
 22→  totalValue: number;
 23→  totalInvested: number;
 24→  totalWithdrawn: number;
 25→}> {
 26→  const investments = await prisma.investment.findMany({
 27→    where: { userId },
 28→    select: {
 29→      currentValue: true,
 30→      totalInvested: true,
 31→      totalWithdrawn: true,
 32→    },
 33→  });
 34→
 35→  let totalValue = 0;
 36→  let totalInvested = 0;
 37→  let totalWithdrawn = 0;
 38→
 39→  for (const investment of investments) {
 40→    totalValue += investment.currentValue;
 41→    totalInvested += investment.totalInvested;
 42→    totalWithdrawn += investment.totalWithdrawn;
 43→  }
 44→
 45→  return { totalValue, totalInvested, totalWithdrawn };
 46→}
 47→
 48→/**
 49→ * Ensure snapshot exists for the previous month (lazy generation)
 50→ * This creates a snapshot for the last month if one doesn't exist
 51→ */
 52→async function ensurePreviousMonthSnapshot(userId: string): Promise<void> {
 53→  const now = new Date();
 54→  const currentMonth = now.getMonth() + 1; // 1-12
 55→  const currentYear = now.getFullYear();
 56→
 57→  // Calculate previous month
 58→  let prevMonth = currentMonth - 1;
 59→  let prevYear = currentYear;
 60→  if (prevMonth === 0) {
 61→    prevMonth = 12;
 62→    prevYear = currentYear - 1;
 63→  }
 64→
 65→  // Check if snapshot for previous month already exists
 66→  const existingSnapshot = await prisma.investmentSnapshot.findUnique({
 67→    where: {
 68→      month_year_userId: {
 69→        month: prevMonth,
 70→        year: prevYear,
 71→        userId,
 72→      },
 73→    },
 74→  });
 75→
 76→  // If snapshot already exists, no need to create one
 77→  if (existingSnapshot) {
 78→    return;
 79→  }
 80→
 81→  // Calculate current totals and save as previous month's snapshot
 82→  // NOTE: This is an approximation - it uses current values for the previous month.
 83→  // If user made changes in the current month before this snapshot was generated,
 84→  // those changes will be reflected in the previous month's snapshot.
 85→  // This trade-off was chosen for simplicity over precise historical tracking.
 86→  // For accurate historical data, users should update values at month-end.
 87→  const totals = await calculateCurrentTotals(userId);
 88→
 89→  // Only create snapshot if user has investments
 90→  if (totals.totalInvested > 0 || totals.totalValue > 0) {
 91→    await prisma.investmentSnapshot.create({
 92→      data: {
 93→        month: prevMonth,
 94→        year: prevYear,
 95→        totalValue: totals.totalValue,
 96→        totalInvested: totals.totalInvested,
 97→        totalWithdrawn: totals.totalWithdrawn,
 98→        userId,
 99→      },
100→    });
101→  }
102→}
103→
104→export async function GET(request: NextRequest): Promise<NextResponse<SnapshotsResponse | { error: string }>> {
105→  try {
106→    const userId = await getAuthenticatedUserId();
107→    const searchParams = request.nextUrl.searchParams;
108→    const monthsParam = searchParams.get("months");
109→    const months = monthsParam ? parseInt(monthsParam, 10) : 12;
110→
111→    // Ensure previous month snapshot exists (lazy generation)
112→    await ensurePreviousMonthSnapshot(userId);
113→
114→    // Calculate date range for fetching snapshots
115→    const now = new Date();
116→    const currentMonth = now.getMonth() + 1;
117→    const currentYear = now.getFullYear();
118→
119→    // Calculate the start date (months ago)
120→    let startMonth = currentMonth - months;
121→    let startYear = currentYear;
122→    while (startMonth <= 0) {
123→      startMonth += 12;
124→      startYear -= 1;
125→    }
126→
127→    // Fetch historical snapshots within the range
128→    const snapshots = await prisma.investmentSnapshot.findMany({
129→      where: {
130→        userId,
131→        OR: [
132→          // Same year, month >= startMonth
133→          {
134→            year: startYear,
135→            month: { gte: startMonth },
136→          },
137→          // Years between start and current (if spanning multiple years)
138→          ...(currentYear > startYear
139→            ? [
140→                {
141→                  year: { gt: startYear, lt: currentYear },
142→                },
143→                // Current year, month <= currentMonth - 1 (not current month)
144→                {
145→                  year: currentYear,
146→                  month: { lt: currentMonth },
147→                },
148→              ]
149→            : []),
150→        ],
151→      },
152→      orderBy: [{ year: "asc" }, { month: "asc" }],
153→    });
154→
155→    // Format snapshots for response
156→    const formattedSnapshots: SnapshotData[] = snapshots.map((snapshot) => ({
157→      month: snapshot.month,
158→      year: snapshot.year,
159→      totalValue: snapshot.totalValue,
160→      totalInvested: snapshot.totalInvested,
161→      totalWithdrawn: snapshot.totalWithdrawn,
162→    }));
163→
164→    // Calculate current totals for the "current" field
165→    const currentTotals = await calculateCurrentTotals(userId);
166→
167→    const current: SnapshotData = {
168→      month: currentMonth,
169→      year: currentYear,
170→      totalValue: currentTotals.totalValue,
171→      totalInvested: currentTotals.totalInvested,
172→      totalWithdrawn: currentTotals.totalWithdrawn,
173→    };
174→
175→    return NextResponse.json({
176→      snapshots: formattedSnapshots,
177→      current,
178→    });
179→  } catch (error) {
180→    if (error instanceof Error && error.message === "Unauthorized") {
181→      return unauthorizedResponse();
182→    }
183→    console.error("Error fetching investment snapshots:", error);
184→    return NextResponse.json(
185→      { error: "Erro ao buscar historico de investimentos" },
186→      { status: 500 }
187→    );
188→  }
189→}
