 10→    const year = parseInt(searchParams.get("year") || String(new Date().getFullYear()), 10);
 11→
 12→    const monthStart = new Date(year, month - 1, 1);
 13→    const monthEnd = new Date(year, month, 0);
 14→    const daysInMonth = monthEnd.getDate();
 15→
 16→    const transactions = await prisma.transaction.findMany({
 17→      where: {
 18→        userId,
 19→        deletedAt: null,
 20→        type: "EXPENSE",
 21→        investmentTransaction: null,
 22→        date: {
 23→          gte: monthStart,
 24→          lte: monthEnd,
 25→        },
 26→      },
 27→      select: {
 28→        description: true,
 29→        amount: true,
 30→        date: true,
 31→      },
 32→      orderBy: {
 33→        date: "asc",
 34→      },
 35→    });
 36→
 37→    // Group transactions by day
 38→    const dayMap = new Map<number, { totalExpense: number; transactionCount: number; transactions: { description: string; amount: number }[] }>();
 39→
 40→    for (const t of transactions) {
 41→      const day = new Date(t.date).getDate();
 42→      const existing = dayMap.get(day) || { totalExpense: 0, transactionCount: 0, transactions: [] };
 43→      const absAmount = Math.abs(t.amount);
 44→      existing.totalExpense += absAmount;
 45→      existing.transactionCount += 1;
 46→      existing.transactions.push({ description: t.description, amount: absAmount });
 47→      dayMap.set(day, existing);
 48→    }
 49→
 50→    // Build days array for ALL days in the month
 51→    let maxExpense = 0;
 52→    const days = [];
 53→
 54→    for (let d = 1; d <= daysInMonth; d++) {
 55→      const dateObj = new Date(year, month - 1, d);
 56→      const dayData = dayMap.get(d);
 57→      const totalExpense = dayData?.totalExpense || 0;
 58→
 59→      if (totalExpense > maxExpense) {
 60→        maxExpense = totalExpense;
 61→      }
 62→
 63→      days.push({
 64→        date: dateObj.toISOString().split("T")[0],
 65→        dayOfMonth: d,
 66→        dayOfWeek: dateObj.getDay(),
 67→        totalExpense,
 68→        transactionCount: dayData?.transactionCount || 0,
 69→        transactions: dayData?.transactions || [],
 70→      });
 71→    }
 72→
 73→    // Compute summary
 74→    const daysWithExpenses = days.filter((d) => d.totalExpense > 0);
 75→    const totalExpenseSum = days.reduce((sum, d) => sum + d.totalExpense, 0);
 76→
 77→    let highestDay = { date: "", total: 0 };
 78→    let lowestDay = { date: "", total: Infinity };
 79→
 80→    for (const d of daysWithExpenses) {
 81→      if (d.totalExpense > highestDay.total) {
 82→        highestDay = { date: d.date, total: d.totalExpense };
 83→      }
 84→      if (d.totalExpense < lowestDay.total) {
 85→        lowestDay = { date: d.date, total: d.totalExpense };
 86→      }
 87→    }
 88→
 89→    if (daysWithExpenses.length === 0) {
 90→      lowestDay = { date: "", total: 0 };
 91→    }
 92→
 93→    const zeroDays = days.filter((d) => d.totalExpense === 0).length;
 94→    const averageDaily = daysInMonth > 0 ? totalExpenseSum / daysInMonth : 0;
 95→
 96→    return NextResponse.json({
 97→      days,
 98→      summary: {
 99→        highestDay,
100→        lowestDay,
101→        averageDaily,
102→        zeroDays,
103→      },
104→      maxExpense,
105→    });
106→  } catch (error) {
