 18→        investmentTransaction: null,
 19→        date: {
 20→          gte: new Date(year, 0, 1),
 21→          lte: new Date(year, 11, 31, 23, 59, 59, 999),
 22→        },
 23→      },
 24→      include: {
 25→        category: true,
 26→      },
 27→    });
 28→
 29→    // Group by category + month
 30→    const categoryMap: Record<
 31→      string,
 32→      {
 33→        categoryId: string;
 34→        categoryName: string;
 35→        categoryColor: string;
 36→        monthlyTotals: number[];
 37→        total: number;
 38→      }
 39→    > = {};
 40→
 41→    for (const t of transactions) {
 42→      if (!t.category || !t.categoryId) continue;
 43→
 44→      const month = new Date(t.date).getMonth(); // 0-11
 45→      const amount = Math.abs(t.amount);
 46→
 47→      if (!categoryMap[t.categoryId]) {
 48→        categoryMap[t.categoryId] = {
 49→          categoryId: t.categoryId,
 50→          categoryName: t.category.name,
 51→          categoryColor: t.category.color,
 52→          monthlyTotals: new Array(12).fill(0),
 53→          total: 0,
 54→        };
 55→      }
 56→
 57→      categoryMap[t.categoryId].monthlyTotals[month] += amount;
 58→      categoryMap[t.categoryId].total += amount;
 59→    }
 60→
 61→    // Calculate trend for each category
 62→    const categories = Object.values(categoryMap).map((cat) => {
 63→      // Average of first 3 months with data
 64→      const first3 = cat.monthlyTotals.slice(0, 3);
 65→      const avgFirst3 = first3.reduce((a, b) => a + b, 0) / 3;
 66→
 67→      // Average of last 3 months with data
 68→      const monthsWithData = cat.monthlyTotals
 69→        .map((val, idx) => ({ val, idx }))
 70→        .filter((m) => m.val > 0);
 71→      const last3Months = monthsWithData.slice(-3);
 72→      const avgLast3 =
 73→        last3Months.length > 0
 74→          ? last3Months.reduce((a, b) => a + b.val, 0) / last3Months.length
 75→          : 0;
 76→
 77→      const trend = avgFirst3 > 0
 78→        ? ((avgLast3 - avgFirst3) / avgFirst3) * 100
 79→        : 0;
 80→
 81→      return {
