 97→        )
 98→      : null;
 99→    const mostShrunk = categoriesWithTrend.length > 0
100→      ? categoriesWithTrend.reduce((min, c) =>
101→          c.trend < min.trend ? c : min
102→        )
103→      : null;
104→
105→    return NextResponse.json({
