107→      categories,
108→      highlights: {
109→        mostGrown: mostGrown
110→          ? { categoryName: mostGrown.categoryName, trend: mostGrown.trend }
111→          : null,
112→        mostShrunk: mostShrunk
113→          ? { categoryName: mostShrunk.categoryName, trend: mostShrunk.trend }
114→          : null,
115→      },
