  8→    const userId = await getAuthenticatedUserId();
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const month = parseInt(searchParams.get("month") || String(new Date().getMonth() + 1), 10);
 11→    const year = parseInt(searchParams.get("year") || String(new Date().getFullYear()), 10);
 12→
 13→    // Calculate 12-month range ending at the given month
 14→    const endDate = new Date(year, month, 0); // last day of target month
 15→    // Start from 11 months before the target month (total of 12 months inclusive)
 16→    const startDate = new Date(year, month - 12, 1);
 17→
 18→    // Fetch 12 months of expense transactions
 19→    const transactions = await prisma.transaction.findMany({
 20→      where: {
 21→        userId,
 22→        deletedAt: null,
 23→        type: "EXPENSE",
 24→        investmentTransaction: null,
 25→        date: {
 26→          gte: startDate,
 27→          lte: endDate,
 28→        },
 29→      },
 30→      select: {
 31→        description: true,
 32→        amount: true,
 33→        date: true,
 34→        isFixed: true,
 35→        categoryId: true,
 36→        category: {
 37→          select: {
 38→            name: true,
 39→          },
 40→        },
 41→      },
 42→      orderBy: {
 43→        date: "asc",
 44→      },
 45→    });
 46→
 47→    // Build monthly breakdown
 48→    const monthlyEntries: { key: string; label: string; fixed: number; variable: number }[] = [];
 49→    const entryMap = new Map<string, { key: string; label: string; fixed: number; variable: number }>();
 50→    for (let i = 0; i < 12; i++) {
 51→      const d = new Date(startDate);
 52→      d.setMonth(d.getMonth() + i);
 53→      const key = `${d.getFullYear()}-${d.getMonth()}`;
 54→      const label = `${MONTH_LABELS[d.getMonth()]}/${String(d.getFullYear()).slice(2)}`;
 55→      const entry = { key, label, fixed: 0, variable: 0 };
 56→      monthlyEntries.push(entry);
 57→      entryMap.set(key, entry);
 58→    }
 59→
 60→    // Aggregate transactions into monthly buckets
 61→    for (const t of transactions) {
 62→      const d = new Date(t.date);
 63→      const key = `${d.getFullYear()}-${d.getMonth()}`;
 64→      const entry = entryMap.get(key);
 65→      if (entry) {
 66→        const absAmount = Math.abs(t.amount);
 67→        if (t.isFixed) {
 68→          entry.fixed += absAmount;
 69→        } else {
 70→          entry.variable += absAmount;
 71→        }
 72→      }
 73→    }
 74→
 75→    const monthlyBreakdown = monthlyEntries.map((e) => ({
 76→      monthLabel: e.label,
 77→      fixed: e.fixed,
 78→      variable: e.variable,
 79→    }));
 80→
 81→    // Current month data
 82→    const currentMonthStart = new Date(year, month - 1, 1);
 83→    const currentMonthEnd = new Date(year, month, 0);
 84→    const currentMonthTransactions = transactions.filter((t) => {
 85→      const d = new Date(t.date);
 86→      return d >= currentMonthStart && d <= currentMonthEnd;
 87→    });
 88→
 89→    const fixed = currentMonthTransactions
 90→      .filter((t) => t.isFixed)
 91→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
 92→
 93→    const variable = currentMonthTransactions
 94→      .filter((t) => !t.isFixed)
 95→      .reduce((sum, t) => sum + Math.abs(t.amount), 0);
 96→
 97→    const total = fixed + variable;
 98→    const fixedPercentage = total > 0 ? (fixed / total) * 100 : 0;
 99→
100→    // Distinct fixed expenses for current month
101→    const fixedTransactions = currentMonthTransactions.filter((t) => t.isFixed);
102→    const seenDescriptions = new Set<string>();
103→    const fixedExpenses: { description: string; amount: number; categoryName: string }[] = [];
104→
105→    for (const t of fixedTransactions) {
106→      if (!seenDescriptions.has(t.description)) {
107→        seenDescriptions.add(t.description);
108→        fixedExpenses.push({
109→          description: t.description,
110→          amount: Math.abs(t.amount),
111→          categoryName: t.category?.name || "Sem categoria",
112→        });
113→      }
114→    }
115→
116→    fixedExpenses.sort((a, b) => b.amount - a.amount);
117→
118→    // Top 10 variable expenses for current month
119→    const topVariableExpenses = currentMonthTransactions
120→      .filter((t) => !t.isFixed)
121→      .map((t) => ({
122→        description: t.description,
123→        amount: Math.abs(t.amount),
124→        categoryName: t.category?.name || "Sem categoria",
125→        date: new Date(t.date).toISOString().split("T")[0],
126→      }))
127→      .sort((a, b) => b.amount - a.amount)
128→      .slice(0, 10);
129→
130→    return NextResponse.json({
131→      currentMonth: {
132→        fixed,
133→        variable,
134→        total,
135→        fixedPercentage,
136→      },
137→      monthlyBreakdown,
138→      fixedExpenses,
139→      topVariableExpenses,
140→    });
141→  } catch (error) {
142→    if (error instanceof Error && error.message === "Unauthorized") {
143→      return unauthorizedResponse();
144→    }
145→    console.error("Error fetching fixed/variable data:", error);
146→    return NextResponse.json(
147→      { error: "Erro ao buscar dados fixos/variaveis" },
148→      { status: 500 }
149→    );
150→  }
151→}
