  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import { getAuthenticatedUserId, unauthorizedResponse } from "@/lib/auth-utils";
  4→import { MONTH_LABELS } from "@/lib/constants";
  5→
  6→export async function GET(request: NextRequest) {
  7→  try {
  8→    const userId = await getAuthenticatedUserId();
  9→    const searchParams = request.nextUrl.searchParams;
 10→    const yearParam = searchParams.get("year");
 11→    const year = yearParam ? parseInt(yearParam, 10) : new Date().getFullYear();
 12→
 13→    const installments = await prisma.installment.findMany({
 14→      where: { userId },
 15→      include: {
 16→        transactions: {
 17→          where: { deletedAt: null },
 18→          orderBy: { date: "asc" },
 19→        },
 20→      },
 21→    });
 22→
 23→    const now = new Date();
 24→    let activeCount = 0;
 25→    let monthlyTotal = 0;
 26→    let totalRemaining = 0;
 27→
 28→    const installmentList = installments.map((inst) => {
 29→      const paidInstallments = inst.transactions.length;
 30→      const remainingInstallments = inst.totalInstallments - paidInstallments;
 31→      const remainingAmount = remainingInstallments * inst.installmentAmount;
 32→      const isActive = paidInstallments < inst.totalInstallments;
 33→
 34→      const startDate = inst.transactions.length > 0
 35→        ? new Date(inst.transactions[0].date)
 36→        : inst.startDate;
 37→
 38→      // Projected end date: startDate + totalInstallments months
 39→      const endDate = new Date(startDate);
 40→      endDate.setMonth(endDate.getMonth() + inst.totalInstallments);
 41→
 42→      if (isActive) {
 43→        activeCount++;
 44→        monthlyTotal += inst.installmentAmount;
 45→        totalRemaining += remainingAmount;
 46→      }
 47→
 48→      return {
 49→        id: inst.id,
 50→        description: inst.description,
 51→        installmentAmount: inst.installmentAmount,
 52→        totalInstallments: inst.totalInstallments,
 53→        paidInstallments,
 54→        remainingInstallments,
 55→        remainingAmount,
 56→        startDate: startDate.toISOString(),
 57→        endDate: endDate.toISOString(),
 58→        isActive,
 59→      };
 60→    });
 61→
 62→    // Sort: active first, then by remaining desc
 63→    installmentList.sort((a, b) => {
 64→      if (a.isActive !== b.isActive) return a.isActive ? -1 : 1;
 65→      return b.remainingInstallments - a.remainingInstallments;
 66→    });
 67→
 68→    // Timeline: for the next 12 months, sum up projected installment amounts
 69→    const timeline = [];
 70→    for (let i = 0; i < 12; i++) {
 71→      const targetMonth = new Date(now.getFullYear(), now.getMonth() + i, 1);
 72→      const monthLabel = MONTH_LABELS[targetMonth.getMonth()];
 73→      let total = 0;
 74→
 75→      for (const inst of installmentList) {
 76→        if (!inst.isActive) continue;
 77→
 78→        const instStart = new Date(inst.startDate);
 79→        const instEnd = new Date(inst.endDate);
 80→
 81→        // Check if this installment is active during the target month
 82→        if (targetMonth >= instStart && targetMonth < instEnd) {
 83→          total += inst.installmentAmount;
 84→        }
 85→      }
 86→
 87→      timeline.push({
 88→        monthLabel: `${monthLabel}/${String(targetMonth.getFullYear()).slice(2)}`,
 89→        total,
 90→      });
 91→    }
 92→
 93→    return NextResponse.json({
 94→      summary: {
 95→        activeCount,
 96→        monthlyTotal,
 97→        totalRemaining,
 98→      },
 99→      timeline,
100→      installments: installmentList,
101→    });
102→  } catch (error) {
103→    if (error instanceof Error && error.message === "Unauthorized") {
104→      return unauthorizedResponse();
105→    }
106→    console.error("Error fetching installments report:", error);
107→    return NextResponse.json(
108→      { error: "Erro ao buscar dados de parcelas" },
109→      { status: 500 }
110→    );
111→  }
112→}
