  1→import { NextRequest, NextResponse } from "next/server";
  2→import prisma from "@/lib/db";
  3→import {
  4→  getAuthenticatedUserId,
  5→  unauthorizedResponse,
  6→} from "@/lib/auth-utils";
  7→import { MONTH_LABELS } from "@/lib/constants";
  8→
  9→export async function GET(request: NextRequest) {
 10→  try {
 11→    const userId = await getAuthenticatedUserId();
 12→    const searchParams = request.nextUrl.searchParams;
 13→    const year = parseInt(
 14→      searchParams.get("year") || String(new Date().getFullYear()),
 15→      10
 16→    );
 17→
 18→    const yearStart = new Date(year, 0, 1);
 19→    const yearEnd = new Date(year, 11, 31, 23, 59, 59, 999);
 20→
 21→    // Query transactions, investment snapshots, and current investment totals in parallel
 22→    const [transactions, snapshots, investmentAggregate] = await Promise.all([
 23→      prisma.transaction.findMany({
 24→        where: {
 25→          userId,
 26→          deletedAt: null,
 27→          investmentTransaction: null,
 28→          date: { gte: yearStart, lte: yearEnd },
 29→        },
 30→        select: { amount: true, type: true, date: true },
 31→      }),
 32→      prisma.investmentSnapshot.findMany({
 33→        where: {
 34→          userId,
 35→          year,
 36→        },
 37→        select: { month: true, totalValue: true },
 38→      }),
 39→      prisma.investment.aggregate({
 40→        where: { userId },
 41→        _sum: { currentValue: true, totalInvested: true },
 42→      }),
 43→    ]);
 44→
 45→    // Build a map of month -> snapshot totalValue
 46→    const snapshotMap = new Map<number, number>();
 47→    for (const snap of snapshots) {
 48→      snapshotMap.set(snap.month, snap.totalValue);
 49→    }
 50→
 51→    // Build monthly income/expense from transactions
 52→    const monthlyIncome = new Array<number>(12).fill(0);
 53→    const monthlyExpense = new Array<number>(12).fill(0);
 54→
 55→    for (const t of transactions) {
 56→      const d = new Date(t.date);
 57→      const monthIndex = d.getMonth(); // 0-based
 58→      if (t.type === "INCOME") {
 59→        monthlyIncome[monthIndex] += t.amount;
 60→      } else {
 61→        monthlyExpense[monthIndex] += Math.abs(t.amount);
 62→      }
 63→    }
 64→
 65→    const currentMonth = new Date().getMonth(); // 0-based
 66→    const isCurrentYear = year === new Date().getFullYear();
 67→    const currentInvestmentValue =
 68→      investmentAggregate._sum.currentValue || 0;
 69→
 70→    let cumulativeCash = 0;
 71→    const months = MONTH_LABELS.map((monthLabel, i) => {
 72→      const income = monthlyIncome[i];
 73→      const expense = monthlyExpense[i];
 74→      const cashDelta = income - expense;
 75→      cumulativeCash += cashDelta;
 76→
 77→      // For the current month of the current year, use live aggregate;
 78→      // otherwise use the snapshot (or 0)
 79→      const investmentValue =
 80→        isCurrentYear && i === currentMonth
 81→          ? currentInvestmentValue
 82→          : snapshotMap.get(i + 1) || 0;
 83→
 84→      const netWorth = cumulativeCash + investmentValue;
 85→
 86→      return {
 87→        monthLabel,
 88→        income,
 89→        expense,
 90→        cashDelta,
 91→        cumulativeCash,
 92→        investmentValue,
 93→        netWorth,
 94→      };
