// DELETE - Permanently delete items older than 30 days or specific item
export async function DELETE(request: NextRequest) {
  try {
    const ctx = await getAuthContext();

    const searchParams = request.nextUrl.searchParams;
    const id = searchParams.get("id");
    const cleanOld = searchParams.get("cleanOld");

    if (id) {
      // Delete specific transaction permanently
      await prisma.transaction.delete({
        where: { id, ...ctx.ownerFilter },
      });
      return NextResponse.json({ success: true, message: "Transacao excluida permanentemente" });
    }

    if (cleanOld === "true") {
      // Delete all transactions deleted more than 30 days ago
      const thirtyDaysAgo = new Date();
      thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

      const result = await prisma.transaction.deleteMany({
        where: {
          ...ctx.ownerFilter,
          deletedAt: {
            not: null,
            lt: thirtyDaysAgo,
          },
        },
      });

      return NextResponse.json({
        success: true,
        message: `${result.count} transacoes antigas excluidas permanentemente`,
        count: result.count,
      });
    }

    return NextResponse.json(
      { error: "Parametro id ou cleanOld=true e obrigatorio" },
      { status: 400 }
    );
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    console.error("Error permanently deleting transactions:", error);
    return NextResponse.json(
      { error: "Erro ao excluir transacoes permanentemente" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { Prisma } from "@prisma/client";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

interface TransactionToCheck {
  description: string;
  amount: number;
  date: string;
  origin?: string;
  isInstallment?: boolean;
  currentInstallment?: number;
  totalInstallments?: number;
}

interface RelatedInstallment {
  index: number;
  relatedTransactionId: string;
  relatedDescription: string;
  relatedInstallment: number;
}

// Extract base description without installment info
// "GRANADO PHARMACIES - Parcela 2/2" -> "GRANADO PHARMACIES"
function extractBaseDescription(description: string): string {
  return description
    .replace(/\s*[-–]\s*Parcela\s*\d+\s*[\/\\]\s*\d+/i, "")
    .replace(/\s*\(\d+\s*[\/\\]\s*\d+\)\s*$/i, "")
    .replace(/\s*Parcela\s*\d+\s*[\/\\]\s*\d+/i, "")
    .replace(/\s*\d+\s*[\/\\]\s*\d+\s*$/i, "")
    .trim();
}

// Detect installment from description
function detectInstallmentFromDescription(description: string): { current: number; total: number } | null {
  const patterns = [
    /[-–]\s*Parcela\s+(\d+)\s*[\/\\]\s*(\d+)/i,
    /Parcela\s+(\d+)\s*[\/\\]\s*(\d+)/i,
    /\((\d+)\s*[\/\\]\s*(\d+)\)/,
    /(\d+)\s*[\/\\]\s*(\d+)/,
  ];

  for (const pattern of patterns) {
    const match = description.match(pattern);
    if (match) {
      const current = parseInt(match[1], 10);
      const total = parseInt(match[2], 10);
      if (current > 0 && total > 1 && current <= total && total <= 48) {
        return { current, total };
      }
    }
  }
  return null;
}

export async function POST(request: NextRequest) {
  try {
    const ctx = await getAuthContext();

    const body = await request.json();
    const { transactions, origin } = body as { transactions: TransactionToCheck[]; origin?: string };

    if (!transactions || !Array.isArray(transactions)) {
      return NextResponse.json(
        { error: "Transacoes nao fornecidas" },
        { status: 400 }
      );
    }

    const duplicates: number[] = [];
    const relatedInstallments: RelatedInstallment[] = [];

    for (let i = 0; i < transactions.length; i++) {
      const t = transactions[i];
      // Parse date safely to avoid timezone issues with YYYY-MM-DD format
      const dateStr = !t.date.includes('T') ? t.date + 'T12:00:00' : t.date;
      const transactionDate = new Date(dateStr);

      // Check for exact duplicates (same date, description, amount, and optionally origin)
      const duplicateWhere: Prisma.TransactionWhereInput = {
        ...ctx.ownerFilter,
        description: {
          contains: t.description.slice(0, 50),
        },
        amount: {
          gte: t.amount - 0.01,
          lte: t.amount + 0.01,
        },
        date: {
          gte: new Date(transactionDate.getTime() - 24 * 60 * 60 * 1000),
          lte: new Date(transactionDate.getTime() + 24 * 60 * 60 * 1000),
        },
        deletedAt: null,
        ...(origin ? { origin } : {}),
      };

      const existing = await prisma.transaction.findFirst({
        where: duplicateWhere,
      });

      if (existing) {
        duplicates.push(i);
        continue;
      }

      // Also check if a recurring expense already has a transaction for this month
      // that is linked to a recurring expense (via recurringExpenseId)
      if (!existing && origin) {
        const recurringDuplicates = await prisma.transaction.findMany({
          where: {
            ...ctx.ownerFilter,
            recurringExpenseId: { not: null },
            origin,
            date: {
              gte: new Date(transactionDate.getFullYear(), transactionDate.getMonth(), 1),
              lt: new Date(transactionDate.getFullYear(), transactionDate.getMonth() + 1, 1),
            },
            deletedAt: null,
          },
          include: { recurringExpense: true },
        });

        // Check if any recurring transaction matches by keyword (reuse normalize+keyword logic)
        const normalizedDesc = t.description.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();
        const isRecurringDuplicate = recurringDuplicates.some((rt) => {
          if (!rt.recurringExpense) return false;
          const keywords = rt.recurringExpense.description
            .toLowerCase()
            .normalize("NFD")
            .replace(/[\u0300-\u036f]/g, "")
            .trim()
            .split(/\s+/)
            .filter((k: string) => k.length > 2);
          return keywords.some((kw: string) => normalizedDesc.includes(kw));
        });

        if (isRecurringDuplicate) {
          duplicates.push(i);
          continue;
        }
      }

      // Check for related installments (sequential installments of same purchase)
      const installmentInfo = detectInstallmentFromDescription(t.description) ||
        (t.isInstallment && t.currentInstallment && t.totalInstallments
          ? { current: t.currentInstallment, total: t.totalInstallments }
          : null);

      if (installmentInfo && installmentInfo.current > 1) {
        const baseDescription = extractBaseDescription(t.description);

        // Look for the previous installment (current - 1)
        const previousInstallment = installmentInfo.current - 1;

        // Search for transactions with similar base description that are installments
        const relatedTransaction = await prisma.transaction.findFirst({
          where: {
            ...ctx.ownerFilter,
            isInstallment: true,
            currentInstallment: previousInstallment,
            totalInstallments: installmentInfo.total,
            amount: {
              gte: t.amount - 1, // Allow small variance
              lte: t.amount + 1,
            },
            deletedAt: null,
          },
        });

        // If not found by exact match, try by description similarity
        if (!relatedTransaction) {
          const similarTransactions = await prisma.transaction.findMany({
            where: {
              ...ctx.ownerFilter,
              isInstallment: true,
              totalInstallments: installmentInfo.total,
              amount: {
                gte: t.amount - 1,
                lte: t.amount + 1,
              },
              deletedAt: null,
            },
          });

          // Find one with matching base description
          for (const st of similarTransactions) {
            const stBase = extractBaseDescription(st.description);
            if (
              stBase.toLowerCase().includes(baseDescription.toLowerCase().slice(0, 20)) ||
              baseDescription.toLowerCase().includes(stBase.toLowerCase().slice(0, 20))
            ) {
              if (st.currentInstallment === previousInstallment) {
                relatedInstallments.push({
                  index: i,
                  relatedTransactionId: st.id,
                  relatedDescription: st.description,
                  relatedInstallment: st.currentInstallment || 0,
                });
                break;
              }
            }
          }
        } else {
          relatedInstallments.push({
            index: i,
            relatedTransactionId: relatedTransaction.id,
            relatedDescription: relatedTransaction.description,
            relatedInstallment: relatedTransaction.currentInstallment || 0,
          });
        }
      }
    }

    return NextResponse.json({
      duplicates,
      hasDuplicates: duplicates.length > 0,
      relatedInstallments,
      hasRelatedInstallments: relatedInstallments.length > 0,
    });
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    console.error("Error checking duplicates:", error);
    return NextResponse.json(
      { error: "Erro ao verificar duplicatas" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

interface TransactionToCheck {
  description: string;
  amount: number;
  date: string;
  origin?: string;
}

interface RecurringMatch {
  index: number;
  recurringExpenseId: string;
  recurringDescription: string;
  recurringAmount: number;
  hasExistingTransaction: boolean;
}

function normalizeText(text: string): string {
  return text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .trim();
}

function matchesRecurring(
  transactionDesc: string,
  recurringDesc: string
): boolean {
  const normalizedTransaction = normalizeText(transactionDesc);
  const normalizedRecurring = normalizeText(recurringDesc);

  const keywords = normalizedRecurring.split(/\s+/).filter((k) => k.length > 2);
  return keywords.some((keyword) => normalizedTransaction.includes(keyword));
}

export async function POST(request: NextRequest) {
  try {
    const ctx = await getAuthContext();
    const body = await request.json();
    const { transactions, origin } = body as {
      transactions: TransactionToCheck[];
      origin?: string;
    };

    if (!transactions || !Array.isArray(transactions)) {
      return NextResponse.json(
        { error: "Transacoes nao fornecidas" },
        { status: 400 }
      );
    }

    // Fetch all active recurring expenses
    const recurringExpenses = await prisma.recurringExpense.findMany({
      where: {
        ...ctx.ownerFilter,
        isActive: true,
      },
      include: {
        transactions: {
          select: { id: true, date: true },
          where: { deletedAt: null },
        },
      },
    });

    const matches: RecurringMatch[] = [];

    for (let i = 0; i < transactions.length; i++) {
      const t = transactions[i];
      const dateStr = !t.date.includes("T") ? t.date + "T12:00:00" : t.date;
      const transactionDate = new Date(dateStr);
      const transactionMonth = transactionDate.getMonth();
      const transactionYear = transactionDate.getFullYear();
      const transactionOrigin = origin || t.origin || "";

      const matchingRecurring = recurringExpenses.filter((recurring) => {
        // Origin must match if both sides have a non-empty value
        if (transactionOrigin && recurring.origin && recurring.origin !== transactionOrigin) {
          return false;
        }

        // Description must match
        if (!matchesRecurring(t.description, recurring.description)) {
          return false;
        }

        return true;
      });

      // Only use if exactly one match (conservative)
      if (matchingRecurring.length === 1) {
        const recurring = matchingRecurring[0];

        // Check if recurring already has a transaction for this month
        const hasExistingTransaction = recurring.transactions.some((tx) => {
          const txDate = new Date(tx.date);
          return (
            txDate.getMonth() === transactionMonth &&
            txDate.getFullYear() === transactionYear
          );
        });

        matches.push({
          index: i,
          recurringExpenseId: recurring.id,
          recurringDescription: recurring.description,
          recurringAmount: recurring.defaultAmount,
          hasExistingTransaction,
        });
      }
    }

    return NextResponse.json({
      matches,
      hasMatches: matches.length > 0,
    });
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    console.error("Error checking recurring matches:", error);
    return NextResponse.json(
      { error: "Erro ao verificar recorrentes" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

export async function GET(request: NextRequest) {
  try {
    const ctx = await getAuthContext();

    const searchParams = request.nextUrl.searchParams;
    const month = searchParams.get("month");
    const year = searchParams.get("year");
    const thresholdParam = searchParams.get("threshold");

    const currentDate = new Date();
    const targetMonth = month ? parseInt(month) : currentDate.getMonth() + 1;
    const targetYear = year ? parseInt(year) : currentDate.getFullYear();
    const threshold = thresholdParam ? parseFloat(thresholdParam) : 2; // Default: 2x average

    // Get transactions for target month
    const startDate = new Date(targetYear, targetMonth - 1, 1);
    const endDate = new Date(targetYear, targetMonth, 0);

    const currentMonthTransactions = await prisma.transaction.findMany({
      where: {
        ...ctx.ownerFilter,
        date: {
          gte: startDate,
          lte: endDate,
        },
        type: "EXPENSE",
        deletedAt: null,
        investmentTransaction: null,
      },
      include: {
        category: true,
      },
    });

    // Get transactions from last 6 months for average calculation
    const sixMonthsAgo = new Date(targetYear, targetMonth - 7, 1);
    const lastMonthEnd = new Date(targetYear, targetMonth - 1, 0);

    const historicalTransactions = await prisma.transaction.findMany({
      where: {
        ...ctx.ownerFilter,
        date: {
          gte: sixMonthsAgo,
          lte: lastMonthEnd,
        },
        type: "EXPENSE",
        deletedAt: null,
        investmentTransaction: null,
      },
      include: {
        category: true,
      },
    });

    // Calculate average per category from historical data
    // Track both total amount and which months had transactions
    const categoryAverages: Record<string, {
      total: number;
      count: number;
      months: Set<string>;
      name: string;
      color: string
    }> = {};

    for (const t of historicalTransactions) {
      if (t.categoryId) {
        if (!categoryAverages[t.categoryId]) {
          categoryAverages[t.categoryId] = {
            total: 0,
            count: 0,
            months: new Set(),
            name: t.category?.name || "Sem categoria",
            color: t.category?.color || "#888888",
          };
        }
        categoryAverages[t.categoryId].total += Math.abs(t.amount);
        categoryAverages[t.categoryId].count += 1;
        // Track which month this transaction belongs to
        const txDate = new Date(t.date);
        const monthKey = `${txDate.getFullYear()}-${txDate.getMonth()}`;
        categoryAverages[t.categoryId].months.add(monthKey);
      }
    }

    // Calculate average transaction amount per category
    const categoryAvgAmounts: Record<string, number> = {};
    for (const [categoryId, data] of Object.entries(categoryAverages)) {
      categoryAvgAmounts[categoryId] = data.count > 0 ? data.total / data.count : 0;
    }

    // Find unusual transactions (amount > threshold * category average)
    // Only consider categories with history in at least 2 different months
    const MIN_MONTHS_FOR_HISTORY = 2;

    const unusualTransactions = currentMonthTransactions
      .filter(t => {
        if (!t.categoryId) return false;
        const categoryData = categoryAverages[t.categoryId];
        // Skip if category doesn't have enough historical data
        if (!categoryData || categoryData.months.size < MIN_MONTHS_FOR_HISTORY) return false;
        const avgAmount = categoryAvgAmounts[t.categoryId];
        if (!avgAmount || avgAmount === 0) return false;
        const amount = Math.abs(t.amount);
        return amount > threshold * avgAmount;
      })
      .map(t => {
        const avgAmount = categoryAvgAmounts[t.categoryId!] || 0;
        const amount = Math.abs(t.amount);
        const exceedsBy = avgAmount > 0 ? ((amount - avgAmount) / avgAmount) * 100 : 0;

        return {
          id: t.id,
          description: t.description,
          amount: amount,
          date: t.date,
          categoryId: t.categoryId,
          categoryName: t.category?.name || null,
          categoryColor: t.category?.color || null,
          categoryAverage: avgAmount,
          exceedsBy,
        };
      })
      .sort((a, b) => b.exceedsBy - a.exceedsBy);

    return NextResponse.json({
      transactions: unusualTransactions,
      threshold,
      period: {
        month: targetMonth,
        year: targetYear,
      },
    });
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    console.error("Error fetching unusual transactions:", error);
    return NextResponse.json(
      { error: "Erro ao buscar transacoes incomuns" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const ctx = await getAuthContext();

    const { id } = await params;
    const body = await request.json();
    const { dayOfMonth, autoGenerate = true } = body;

    // Fetch the transaction
    const transaction = await prisma.transaction.findUnique({
      where: { id, ...ctx.ownerFilter },
      include: { category: true },
    });

    if (!transaction) {
      return NextResponse.json(
        { error: "Transacao nao encontrada" },
        { status: 404 }
      );
    }

    // Check if transaction is already linked to a recurring expense
    if (transaction.recurringExpenseId) {
      return NextResponse.json(
        { error: "Esta transacao ja esta vinculada a uma despesa recorrente" },
        { status: 400 }
      );
    }

    // Check if transaction is an installment
    if (transaction.isInstallment || transaction.installmentId) {
      return NextResponse.json(
        { error: "Transacoes parceladas nao podem ser marcadas como recorrentes" },
        { status: 400 }
      );
    }

    // Calculate day of month from transaction date if not provided
    const transactionDate = new Date(transaction.date);
    const calculatedDayOfMonth = dayOfMonth || transactionDate.getDate();

    // Create the recurring expense and link the transaction in a single transaction
    const result = await prisma.$transaction(async (tx) => {
      // Create the recurring expense
      const recurringExpense = await tx.recurringExpense.create({
        data: {
          description: transaction.description,
          defaultAmount: Math.abs(transaction.amount),
          dayOfMonth: calculatedDayOfMonth,
          type: transaction.type,
          origin: transaction.origin,
          categoryId: transaction.categoryId,
          isActive: true,
          autoGenerate,
          userId: ctx.userId,
          spaceId: ctx.spaceId,
        },
      });

      // Update the transaction to link it to the recurring expense and mark as fixed
      const updatedTransaction = await tx.transaction.update({
        where: { id, ...ctx.ownerFilter },
        data: {
          recurringExpenseId: recurringExpense.id,
          isFixed: true,
        },
        include: {
          category: true,
          recurringExpense: true,
        },
      });

      return { recurringExpense, transaction: updatedTransaction };
    });

    return NextResponse.json(result);
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    console.error("Error making transaction recurring:", error);
    return NextResponse.json(
      { error: "Erro ao criar despesa recorrente" },
      { status: 500 }
    );
  }
}

