import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const ctx = await getAuthContext();

    const { id } = await params;
    const body = await request.json();
    const { month, year, amount } = body;

    if (!month || !year) {
      return NextResponse.json(
        { error: "Mes e ano sao obrigatorios" },
        { status: 400 }
      );
    }

    const recurringExpense = await prisma.recurringExpense.findUnique({
      where: { id, ...ctx.ownerFilter },
    });

    if (!recurringExpense) {
      return NextResponse.json(
        { error: "Despesa recorrente nao encontrada" },
        { status: 404 }
      );
    }

    // Check if this recurring expense should be auto-generated
    if (!recurringExpense.autoGenerate) {
      return NextResponse.json(
        { error: "Esta despesa aguarda vinculacao via importacao de fatura. Desative 'Gerar automaticamente' se quiser gerar manualmente." },
        { status: 400 }
      );
    }

    // Check if transaction already exists for this month
    const startOfMonth = new Date(year, month - 1, 1);
    const endOfMonth = new Date(year, month, 0);

    const existingTransaction = await prisma.transaction.findFirst({
      where: {
        recurringExpenseId: id,
        ...ctx.ownerFilter,
        date: {
          gte: startOfMonth,
          lte: endOfMonth,
        },
      },
    });

    if (existingTransaction) {
      return NextResponse.json(
        { error: "Ja existe uma transacao para este mes", transaction: existingTransaction },
        { status: 400 }
      );
    }

    // Calculate the date (use dayOfMonth, but cap at last day of month)
    const lastDayOfMonth = new Date(year, month, 0).getDate();
    const day = Math.min(recurringExpense.dayOfMonth, lastDayOfMonth);
    const transactionDate = new Date(year, month - 1, day);

    // Use custom amount or default amount
    const finalAmount = amount !== undefined ? Math.abs(amount) : recurringExpense.defaultAmount;

    const transaction = await prisma.transaction.create({
      data: {
        description: recurringExpense.description,
        amount: recurringExpense.type === "EXPENSE" ? -finalAmount : finalAmount,
        date: transactionDate,
        type: recurringExpense.type,
        origin: recurringExpense.origin,
        categoryId: recurringExpense.categoryId,
        isFixed: true,
        recurringExpenseId: id,
        userId: ctx.userId,
        spaceId: ctx.spaceId,
        createdByUserId: ctx.userId,
      },
      include: {
        category: true,
        recurringExpense: true,
      },
    });

    return NextResponse.json(transaction, { status: 201 });
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    return unauthorizedResponse();
  }
}

import { NextRequest, NextResponse } from "next/server";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

export async function GET(request: NextRequest) {
  try {
    const ctx = await getAuthContext();

    const searchParams = request.nextUrl.searchParams;
    const month = parseInt(searchParams.get("month") || String(new Date().getMonth() + 1));
    const year = parseInt(searchParams.get("year") || String(new Date().getFullYear()));

    const startOfMonth = new Date(year, month - 1, 1);
    const endOfMonth = new Date(year, month, 0);

    // Find recurring expenses with autoGenerate = false that don't have a transaction this month
    const recurringExpenses = await prisma.recurringExpense.findMany({
      where: {
        autoGenerate: false,
        isActive: true,
        ...ctx.ownerFilter,
      },
      include: {
        category: true,
        transactions: {
          where: {
            date: {
              gte: startOfMonth,
              lte: endOfMonth,
            },
          },
        },
      },
    });

    // Filter to only those without transactions this month
    const pending = recurringExpenses.filter(
      (expense) => expense.transactions.length === 0
    );

    return NextResponse.json({
      month,
      year,
      pending: pending.map((expense) => ({
        id: expense.id,
        description: expense.description,
        defaultAmount: expense.defaultAmount,
        dayOfMonth: expense.dayOfMonth,
        type: expense.type,
        origin: expense.origin,
        category: expense.category,
      })),
      count: pending.length,
    });
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    return unauthorizedResponse();
  }
}

import { NextResponse } from "next/server";
import prisma from "@/lib/db";
import { getAuthContext, unauthorizedResponse, forbiddenResponse } from "@/lib/auth-utils";

interface PatternMatch {
  description: string;
  normalizedDescription: string;
  avgAmount: number;
  occurrences: number;
  avgDayOfMonth: number;
  categoryId: string | null;
  categoryName: string | null;
  origin: string;
}

function normalizeDescription(desc: string): string {
  // Remove installment patterns like "1/10", "PARCELA 1 DE 10"
  let normalized = desc
    .replace(/\d+\s*(?:\/|DE)\s*\d+/gi, "")
    .replace(/PARCELA/gi, "")
    .trim();

  // Remove common prefixes/suffixes that vary
  normalized = normalized
    .replace(/\s*-\s*\d+$/g, "")
    .replace(/^\d+\s*-\s*/g, "")
    .trim();

  // Remove extra whitespace
  normalized = normalized.replace(/\s+/g, " ").toUpperCase();

  return normalized;
}

export async function GET() {
  try {
    const ctx = await getAuthContext();

    // Get the last 6 months of transactions
    const sixMonthsAgo = new Date();
    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

    const transactions = await prisma.transaction.findMany({
      where: {
        date: { gte: sixMonthsAgo },
        type: "EXPENSE",
        isInstallment: false,
        recurringExpenseId: null,
        ...ctx.ownerFilter,
      },
      include: {
        category: true,
      },
      orderBy: {
        date: "desc",
      },
    });

    // Get existing recurring expenses to exclude from suggestions
    const existingRecurring = await prisma.recurringExpense.findMany({
      where: { ...ctx.ownerFilter },
      select: { description: true },
    });
    const existingDescriptions = new Set(
      existingRecurring.map((r) => normalizeDescription(r.description))
    );

    // Group transactions by normalized description
    const groups: Record<string, {
      transactions: typeof transactions;
      normalizedDesc: string;
    }> = {};

    for (const t of transactions) {
      const normalized = normalizeDescription(t.description);
      if (!normalized) continue;

      if (!groups[normalized]) {
        groups[normalized] = {
          transactions: [],
          normalizedDesc: normalized,
        };
      }
      groups[normalized].transactions.push(t);
    }

    // Analyze patterns - look for transactions that appear 3+ times
    const suggestions: PatternMatch[] = [];

    for (const [key, group] of Object.entries(groups)) {
      // Skip if this pattern already exists as a recurring expense
      if (existingDescriptions.has(key)) continue;

      // Need at least 3 occurrences to suggest
      if (group.transactions.length < 3) continue;

      // Check if they are in different months
      const monthSet = new Set(
        group.transactions.map((t) => {
          const d = new Date(t.date);
          return `${d.getFullYear()}-${d.getMonth()}`;
        })
      );

      // Need at least 2 different months
      if (monthSet.size < 2) continue;

      // Calculate average values
      const amounts = group.transactions.map((t) => Math.abs(t.amount));
      const avgAmount = amounts.reduce((a, b) => a + b, 0) / amounts.length;

      const days = group.transactions.map((t) => new Date(t.date).getDate());
      const avgDayOfMonth = Math.round(
        days.reduce((a, b) => a + b, 0) / days.length
      );

      // Use the most recent transaction for category and origin
      const latest = group.transactions[0];

      suggestions.push({
        description: latest.description,
        normalizedDescription: key,
        avgAmount,
        occurrences: group.transactions.length,
        avgDayOfMonth,
        categoryId: latest.categoryId,
        categoryName: latest.category?.name || null,
        origin: latest.origin,
      });
    }

    // Sort by occurrence count (most frequent first)
    suggestions.sort((a, b) => b.occurrences - a.occurrences);

    return NextResponse.json(suggestions.slice(0, 10));
  } catch (error) {
    if (error instanceof Error && error.message === "Unauthorized") {
      return unauthorizedResponse();
    }
    if (error instanceof Error && error.message === "Forbidden") {
      return forbiddenResponse();
    }
    return unauthorizedResponse();
  }
}

