 15→import { useToast } from "@/components/ui/use-toast";
 16→import type { Transaction, Category, Origin } from "@/types";
 17→
 18→interface Props {
 19→  categories: Category[];
 20→  origins: Origin[];
 21→  transaction?: Transaction | null;
 22→  onSuccess: () => void;
 23→  onCancel: () => void;
 24→}
 25→
 26→export function TransactionForm({
 27→  categories,
 28→  origins,
 29→  transaction,
 30→  onSuccess,
 31→  onCancel,
 32→}: Props) {
 33→  const { toast } = useToast();
 34→  const [loading, setLoading] = useState(false);
 35→
 36→  const [description, setDescription] = useState(transaction?.description || "");
 37→  const [amount, setAmount] = useState(
 38→    transaction ? String(Math.abs(transaction.amount)) : ""
 39→  );
 40→  const [date, setDate] = useState(
 41→    transaction
 42→      ? new Date(transaction.date).toISOString().split("T")[0]
 43→      : new Date().toISOString().split("T")[0]
 44→  );
 45→  const [type, setType] = useState<"INCOME" | "EXPENSE" | "TRANSFER">(
 46→    transaction?.type as "INCOME" | "EXPENSE" | "TRANSFER" || "EXPENSE"
 47→  );
 48→  const [origin, setOrigin] = useState(transaction?.origin || "");
 49→  const [categoryId, setCategoryId] = useState(transaction?.categoryId || "");
 50→  const [isFixed, setIsFixed] = useState(transaction?.isFixed || false);
 51→  const [isInstallment, setIsInstallment] = useState(transaction?.isInstallment || false);
 52→  const [currentInstallment, setCurrentInstallment] = useState(
 53→    transaction?.currentInstallment ? String(transaction.currentInstallment) : "1"
 54→  );
 55→  const [totalInstallments, setTotalInstallments] = useState(
 56→    transaction?.totalInstallments
 57→      ? String(transaction.totalInstallments)
 58→      : transaction?.installment?.totalInstallments
 59→      ? String(transaction.installment.totalInstallments)
 60→      : "2"
 61→  );
 62→  const [tagsInput, setTagsInput] = useState(
 63→    transaction?.tags ? JSON.parse(transaction.tags).join(", ") : ""
 64→  );
 65→
 66→  async function handleSubmit(e: React.FormEvent) {
 67→    e.preventDefault();
 68→
 69→    if (!description || !amount || !date || !origin) {
 70→      toast({
 71→        title: "Erro",
 72→        description: "Preencha todos os campos obrigatorios",
 73→        variant: "destructive",
 74→      });
 75→      return;
 76→    }
 77→
 78→    setLoading(true);
 79→
 80→    // Process tags - split by comma and trim
 81→    const tagsArray = tagsInput
 82→      .split(",")
 83→      .map((t: string) => t.trim())
 84→      .filter((t: string) => t.length > 0);
 85→
 86→    try {
 87→      const payload = {
 88→        description,
 89→        amount: parseFloat(amount),
 90→        date,
 91→        type,
 92→        origin,
 93→        categoryId: categoryId || null,
 94→        isFixed,
 95→        isInstallment,
 96→        currentInstallment: isInstallment ? parseInt(currentInstallment) : null,
 97→        totalInstallments: isInstallment ? parseInt(totalInstallments) : null,
 98→        installmentAmount: isInstallment && !transaction ? parseFloat(amount) : undefined,
 99→        tags: tagsArray.length > 0 ? tagsArray : null,
100→      };
101→
102→      const url = transaction
103→        ? `/api/transactions/${transaction.id}`
104→        : "/api/transactions";
105→
106→      const res = await fetch(url, {
107→        method: transaction ? "PUT" : "POST",
108→        headers: { "Content-Type": "application/json" },
109→        body: JSON.stringify(payload),
110→      });
111→
112→      if (!res.ok) {
113→        throw new Error("Erro ao salvar transacao");
114→      }
115→
116→      toast({
117→        title: "Sucesso",
118→        description: transaction
119→          ? "Transacao atualizada com sucesso"
120→          : isInstallment
121→          ? `${totalInstallments} parcelas criadas com sucesso`
122→          : "Transacao criada com sucesso",
123→      });
124→
125→      onSuccess();
126→    } catch (error) {
127→      toast({
128→        title: "Erro",
129→        description: "Ocorreu um erro ao salvar a transacao",
130→        variant: "destructive",
131→      });
132→    } finally {
133→      setLoading(false);
134→    }
135→  }
136→
137→  return (
138→    <form onSubmit={handleSubmit} className="space-y-4">
139→      <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
140→        <div
141→          className={`cursor-pointer rounded-lg border-2 p-3 text-center transition-colors ${
142→            type === "EXPENSE"
143→              ? "border-red-500 bg-red-50 text-red-700"
144→              : "border-gray-200 hover:border-gray-300"
145→          }`}
146→          onClick={() => setType("EXPENSE")}
147→        >
148→          Despesa
149→        </div>
150→        <div
151→          className={`cursor-pointer rounded-lg border-2 p-3 text-center transition-colors ${
152→            type === "INCOME"
153→              ? "border-green-500 bg-green-50 text-green-700"
154→              : "border-gray-200 hover:border-gray-300"
155→          }`}
156→          onClick={() => setType("INCOME")}
157→        >
158→          Receita
159→        </div>
160→        <div
161→          className={`cursor-pointer rounded-lg border-2 p-3 text-center transition-colors ${
162→            type === "TRANSFER"
163→              ? "border-gray-500 bg-gray-100 text-gray-700"
164→              : "border-gray-200 hover:border-gray-300"
165→          }`}
166→          onClick={() => setType("TRANSFER")}
167→        >
168→          Transferencia
169→        </div>
170→      </div>
171→
172→      <div>
173→        <Label htmlFor="description">Descricao *</Label>
174→        <Input
175→          id="description"
176→          value={description}
177→          onChange={(e) => setDescription(e.target.value)}
178→          placeholder="Ex: Supermercado"
179→        />
180→      </div>
181→
182→      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
183→        <div>
184→          <Label htmlFor="amount">Valor *</Label>
185→          <Input
186→            id="amount"
187→            type="number"
188→            step="0.01"
189→            min="0"
190→            value={amount}
191→            onChange={(e) => setAmount(e.target.value)}
192→            placeholder="0,00"
193→            className="w-full"
194→          />
195→        </div>
196→
197→        <div>
198→          <Label htmlFor="date">Data *</Label>
199→          <Input
200→            id="date"
201→            type="date"
202→            value={date}
203→            onChange={(e) => setDate(e.target.value)}
204→            className="w-full"
205→          />
206→        </div>
207→      </div>
208→
209→      <div>
210→        <Label htmlFor="origin">Origem *</Label>
211→        <Select value={origin} onValueChange={setOrigin}>
212→          <SelectTrigger>
213→            <SelectValue placeholder="Selecione a origem" />
214→          </SelectTrigger>
215→          <SelectContent>
216→            {origins.map((o) => (
217→              <SelectItem key={o.id} value={o.name}>
218→                {o.name}
219→              </SelectItem>
220→            ))}
221→          </SelectContent>
222→        </Select>
223→      </div>
224→
225→      <div>
226→        <Label htmlFor="category">Categoria</Label>
227→        <Select value={categoryId} onValueChange={setCategoryId}>
228→          <SelectTrigger>
229→            <SelectValue placeholder="Selecione a categoria" />
230→          </SelectTrigger>
231→          <SelectContent>
232→            {categories.map((c) => (
233→              <SelectItem key={c.id} value={c.id}>
234→                <div className="flex items-center gap-2">
235→                  <div
236→                    className="h-3 w-3 rounded-full"
237→                    style={{ backgroundColor: c.color }}
238→                  />
239→                  {c.name}
240→                </div>
241→              </SelectItem>
242→            ))}
243→          </SelectContent>
244→        </Select>
245→      </div>
246→
247→      <div>
248→        <Label htmlFor="tags">Tags (opcional)</Label>
249→        <Input
250→          id="tags"
251→          value={tagsInput}
252→          onChange={(e) => setTagsInput(e.target.value)}
253→          placeholder="Ex: trabalho, viagem, reuniao"
254→        />
255→        <p className="mt-1 text-xs text-gray-500">
256→          Separe as tags por virgula
257→        </p>
258→      </div>
259→
260→      <div className="flex items-center justify-between">
261→        <div className="flex items-center gap-2">
262→          <Switch
263→            id="isFixed"
264→            checked={isFixed}
265→            onCheckedChange={setIsFixed}
266→            disabled={isInstallment}
