  1→// src/app/api/spaces/route.ts
  2→import { NextResponse } from 'next/server'
  3→import prisma from '@/lib/db'
  4→import { getAuthenticatedUserId, unauthorizedResponse } from '@/lib/auth-utils'
  5→
  6→export async function GET() {
  7→  try {
  8→    const userId = await getAuthenticatedUserId()
  9→
 10→    const memberships = await prisma.spaceMember.findMany({
 11→      where: { userId },
 12→      include: {
 13→        space: {
 14→          select: { id: true, name: true, createdBy: true, createdAt: true },
 15→        },
 16→      },
 17→    })
 18→
 19→    return NextResponse.json(memberships)
 20→  } catch (error) {
 21→    if (error instanceof Error && error.message === 'Unauthorized') {
 22→      return unauthorizedResponse()
 23→    }
 24→    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
 25→  }
 26→}
 27→
 28→export async function POST(request: Request) {
 29→  try {
 30→    const userId = await getAuthenticatedUserId()
 31→    const body = await request.json()
 32→    const { name } = body
 33→
 34→    if (!name || typeof name !== 'string' || name.trim().length === 0) {
