  onCancel: vi.fn(),
}

describe('TransactionForm - isPrivate toggle', () => {
  beforeEach(() => {
    mockFetch.mockReset()
  })

  it('should show privacy toggle when user has spaces', async () => {
    // /api/spaces returns at least one membership
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => [{ id: 'm1', spaceId: 's1', space: { id: 's1', name: 'Família' } }],
    })

    render(<TransactionForm {...defaultProps} />)

    await waitFor(() => {
      expect(screen.getByLabelText('Transação privada')).toBeInTheDocument()
    })
  })

  it('should NOT show privacy toggle when user has no spaces', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => [],
    })

    render(<TransactionForm {...defaultProps} />)

    // Wait for fetch to complete, then verify toggle is absent
    await waitFor(() => {
      expect(mockFetch).toHaveBeenCalledWith('/api/spaces')
    })

    expect(screen.queryByLabelText('Transação privada')).not.toBeInTheDocument()
  })

  it('should include isPrivate in payload when submitting', async () => {
    const user = userEvent.setup()

    // First call: /api/spaces
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => [{ id: 'm1', spaceId: 's1', space: { id: 's1', name: 'Família' } }],
    })

    render(<TransactionForm {...defaultProps} />)

    // Wait for toggle to appear
    await waitFor(() => {
      expect(screen.getByLabelText('Transação privada')).toBeInTheDocument()
    })

    // Toggle the privacy switch ON
    const privacySwitch = screen.getByRole('switch', { name: 'Transação privada' })
    await user.click(privacySwitch)

    // Fill in required fields
    await user.type(screen.getByLabelText('Descrição *'), 'Teste privado')
    await user.type(screen.getByLabelText('Valor *'), '100')

    // Mock the transaction POST
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => ({ id: 't1' }),
    })

    // Submit the form
    await user.click(screen.getByRole('button', { name: 'Criar' }))

    await waitFor(() => {
      // Find the POST call (not the /api/spaces GET)
      const postCall = mockFetch.mock.calls.find(
        (call) => call[1]?.method === 'POST'
      )
      expect(postCall).toBeDefined()
      const body = JSON.parse(postCall![1].body)
      expect(body.isPrivate).toBe(true)
    })
  })

  it('should default isPrivate to false', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => [{ id: 'm1', spaceId: 's1', space: { id: 's1', name: 'Família' } }],
    })

    render(<TransactionForm {...defaultProps} />)

    await waitFor(() => {
      const toggle = screen.getByRole('switch', { name: 'Transação privada' })
      expect(toggle).toBeInTheDocument()
      expect(toggle).not.toBeChecked()
    })
  })
})

import { describe, it, expect, vi, beforeEach } from 'vitest'
import { render, screen, waitFor, fireEvent } from '@testing-library/react'
import { SpaceSwitcher } from './SpaceSwitcher'

// Mock fetch globally
const mockFetch = vi.fn()
global.fetch = mockFetch

// Mock window.location.reload
const mockReload = vi.fn()
Object.defineProperty(window, 'location', {
  value: { reload: mockReload },
  writable: true,
})

const mockMemberships = [
  {
    role: 'ADMIN',
    space: { id: 'space-1', name: 'Família Silva' },
  },
]

describe('SpaceSwitcher', () => {
  beforeEach(() => {
    mockFetch.mockReset()
    mockReload.mockReset()
  })

  it('renders nothing when user has no spaces', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve([]),
    })

    const { container } = render(<SpaceSwitcher />)

    await waitFor(() => {
      expect(container.innerHTML).toBe('')
    })
  })

  it('renders switcher when user has spaces', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockMemberships),
    })

    render(<SpaceSwitcher />)

    await waitFor(() => {
      expect(screen.getByText('Minha Conta')).toBeInTheDocument()
    })
  })

  it('shows personal account as default label', async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: () => Promise.resolve(mockMemberships),
    })

    render(<SpaceSwitcher />)

    await waitFor(() => {
      expect(screen.getByText('Minha Conta')).toBeInTheDocument()
    })
  })

  it('switches to space when clicked', async () => {
    mockFetch
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve(mockMemberships),
      })
      .mockResolvedValueOnce({
        ok: true,
        json: () => Promise.resolve({ activeSpaceId: 'space-1' }),
      })

    render(<SpaceSwitcher />)

    await waitFor(() => {
      expect(screen.getByText('Minha Conta')).toBeInTheDocument()
