 1→// src/app/api/invites/[code]/accept/route.ts
 2→import { NextResponse } from 'next/server'
 3→import prisma from '@/lib/db'
 4→import { getAuthenticatedUserId, unauthorizedResponse } from '@/lib/auth-utils'
 5→import { auth } from '@/auth'
 6→
 7→export async function POST(
 8→  request: Request,
 9→  { params }: { params: Promise<{ code: string }> }
10→) {
11→  try {
12→    const userId = await getAuthenticatedUserId()
13→    const { code } = await params
14→
15→    const invite = await prisma.spaceInvite.findUnique({
16→      where: { code },
17→      include: { space: true },
18→    })
19→
20→    if (!invite || invite.status !== 'PENDING') {
21→      return NextResponse.json({ error: 'Convite inválido' }, { status: 404 })
22→    }
23→
24→    if (invite.expiresAt < new Date()) {
25→      await prisma.spaceInvite.update({
26→        where: { id: invite.id },
27→        data: { status: 'EXPIRED' },
28→      })
29→      return NextResponse.json({ error: 'Convite expirado' }, { status: 410 })
30→    }
31→
32→    // MVP: limitar a um espaço por usuário
33→    const existingMemberships = await prisma.spaceMember.findMany({
34→      where: { userId },
35→    })
36→    if (existingMemberships.length > 0) {
37→      return NextResponse.json(
38→        { error: 'Você já participa de um espaço. No momento, só é possível participar de um espaço.' },
39→        { status: 409 }
40→      )
41→    }
42→
43→    // Verify email match for email-targeted invites
44→    if (invite.email) {
45→      const session = await auth()
46→      if (session?.user?.email?.toLowerCase() !== invite.email.toLowerCase()) {
47→        return NextResponse.json({ error: 'Este convite foi enviado para outro email' }, { status: 403 })
48→      }
49→    }
50→
51→    // Check if already a member
52→    const existingMember = await prisma.spaceMember.findUnique({
53→      where: {
54→        spaceId_userId: { spaceId: invite.spaceId, userId },
55→      },
56→    })
57→
58→    if (existingMember) {
59→      return NextResponse.json({ error: 'Já é membro deste espaço' }, { status: 409 })
60→    }
61→
62→    // Add as member and mark invite as accepted
63→    await prisma.$transaction([
64→      prisma.spaceMember.create({
65→        data: {
66→          spaceId: invite.spaceId,
67→          userId,
68→          role: invite.role,
69→        },
70→      }),
71→      prisma.spaceInvite.update({
72→        where: { id: invite.id },
73→        data: { status: 'ACCEPTED' },
74→      }),
75→    ])
76→
77→    return NextResponse.json({
78→      message: 'Convite aceito',
79→      space: invite.space,
80→    })
81→  } catch (error) {
82→    if (error instanceof Error && error.message === 'Unauthorized') {
83→      return unauthorizedResponse()
84→    }
85→    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
86→  }
87→}
