 1→// src/lib/space-context.ts
 2→import prisma from '@/lib/db'
 3→import { cookies } from 'next/headers'
 4→
 5→type SpaceRole = 'ADMIN' | 'MEMBER' | 'LIMITED'
 6→
 7→export class SpacePermissions {
 8→  constructor(private role: SpaceRole) {}
 9→
10→  canViewTransactions(): boolean {
11→    return true // all roles
12→  }
13→
14→  canEditTransactions(): boolean {
15→    return true // all roles (LIMITED edits only own)
16→  }
17→
18→  canViewAllTransactions(): boolean {
19→    return this.role !== 'LIMITED'
20→  }
21→
22→  canViewInvestments(): boolean {
23→    return this.role === 'ADMIN' || this.role === 'MEMBER'
24→  }
25→
26→  canViewBudgets(): boolean {
27→    return this.role === 'ADMIN' || this.role === 'MEMBER'
28→  }
29→
30→  canManageSpace(): boolean {
31→    return this.role === 'ADMIN'
32→  }
33→
34→  canViewIncomes(): boolean {
35→    return this.role === 'ADMIN' || this.role === 'MEMBER'
36→  }
37→}
38→
39→export async function validateSpaceAccess(userId: string, spaceId: string) {
40→  const membership = await prisma.spaceMember.findUnique({
41→    where: {
42→      spaceId_userId: { spaceId, userId },
43→    },
44→  })
45→
46→  if (!membership) {
47→    throw new Error('Forbidden')
48→  }
49→
50→  return membership
51→}
52→
53→export async function getActiveSpaceId(): Promise<string | null> {
54→  const cookieStore = await cookies()
55→  return cookieStore.get('activeSpaceId')?.value ?? null
56→}
57→
58→export async function setActiveSpaceId(spaceId: string | null): Promise<void> {
59→  const cookieStore = await cookies()
60→  if (spaceId) {
61→    cookieStore.set('activeSpaceId', spaceId, {
62→      httpOnly: true,
63→      secure: process.env.NODE_ENV === 'production',
64→      sameSite: 'lax',
65→      path: '/',
66→      maxAge: 60 * 60 * 24 * 365, // 1 year
67→    })
68→  } else {
69→    cookieStore.delete('activeSpaceId')
70→  }
71→}
