 62→async function copyUserDataToSpace(userId: string, spaceId: string) {
 63→  // Copy categories
 64→  const categories = await prisma.category.findMany({
 65→    where: { userId, spaceId: null },
 66→  })
 67→  if (categories.length > 0) {
 68→    await prisma.category.createMany({
 69→      data: categories.map((c) => ({
 70→        name: c.name,
 71→        color: c.color,
 72→        icon: c.icon,
 73→        userId,
 74→        spaceId,
 75→      })),
 76→    })
 77→  }
 78→
 79→  // Copy origins
 80→  const origins = await prisma.origin.findMany({
 81→    where: { userId, spaceId: null },
 82→  })
 83→  if (origins.length > 0) {
 84→    await prisma.origin.createMany({
 85→      data: origins.map((o) => ({
 86→        name: o.name,
 87→        userId,
 88→        spaceId,
 89→      })),
 90→    })
 91→  }
 92→
 93→  // Copy investment categories
 94→  const investmentCategories = await prisma.investmentCategory.findMany({
 95→    where: { userId, spaceId: null },
 96→  })
 97→  if (investmentCategories.length > 0) {
 98→    await prisma.investmentCategory.createMany({
 99→      data: investmentCategories.map((ic) => ({
100→        name: ic.name,
101→        icon: ic.icon,
102→        color: ic.color,
103→        userId,
104→        spaceId,
105→      })),
106→    })
107→  }
108→
109→  // Copy category rules (need new category IDs)
110→  const spaceCategories = await prisma.category.findMany({
111→    where: { userId, spaceId },
112→  })
113→  const categoryNameToId = new Map(spaceCategories.map((c) => [c.name, c.id]))
114→
115→  const rules = await prisma.categoryRule.findMany({
116→    where: { userId, spaceId: null },
117→    include: { category: true },
118→  })
119→  const rulesToCreate = rules
120→    .filter((r) => categoryNameToId.has(r.category.name))
121→    .map((r) => ({
122→      keyword: r.keyword,
123→      categoryId: categoryNameToId.get(r.category.name)!,
124→      userId,
125→      spaceId,
126→    }))
127→  if (rulesToCreate.length > 0) {
128→    await prisma.categoryRule.createMany({ data: rulesToCreate })
129→  }
130→}
