 8→export async function GET(
 9→  request: Request,
10→  { params }: { params: Promise<{ spaceId: string }> }
11→) {
12→  try {
13→    const userId = await getAuthenticatedUserId()
14→    const { spaceId } = await params
15→    const membership = await validateSpaceAccess(userId, spaceId)
16→    const perms = new SpacePermissions(membership.role)
17→
18→    if (!perms.canManageSpace()) {
19→      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
20→    }
21→
22→    const invites = await prisma.spaceInvite.findMany({
23→      where: { spaceId, status: 'PENDING' },
24→      orderBy: { createdAt: 'desc' },
25→    })
26→
27→    return NextResponse.json(invites)
28→  } catch (error) {
29→    if (error instanceof Error && error.message === 'Unauthorized') {
30→      return unauthorizedResponse()
31→    }
32→    if (error instanceof Error && error.message === 'Forbidden') {
33→      return NextResponse.json({ error: 'Sem acesso ao espaço' }, { status: 403 })
34→    }
35→    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
36→  }
37→}
38→
39→export async function POST(
40→  request: Request,
41→  { params }: { params: Promise<{ spaceId: string }> }
42→) {
43→  try {
44→    const userId = await getAuthenticatedUserId()
45→    const { spaceId } = await params
46→    const membership = await validateSpaceAccess(userId, spaceId)
47→    const perms = new SpacePermissions(membership.role)
48→
49→    if (!perms.canManageSpace()) {
50→      return NextResponse.json({ error: 'Sem permissão' }, { status: 403 })
51→    }
52→
53→    const body = await request.json()
54→    const { email, role } = body
55→
56→    if (!role || !['ADMIN', 'MEMBER', 'LIMITED'].includes(role)) {
57→      return NextResponse.json({ error: 'Role inválido' }, { status: 400 })
58→    }
59→
60→    const code = randomBytes(16).toString('hex')
61→    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000) // 7 days
62→
63→    const invite = await prisma.spaceInvite.create({
64→      data: {
65→        spaceId,
66→        email: email?.toLowerCase() || null,
67→        code,
68→        role,
69→        expiresAt,
70→      },
71→    })
72→
73→    return NextResponse.json(invite, { status: 201 })
74→  } catch (error) {
75→    if (error instanceof Error && error.message === 'Unauthorized') {
76→      return unauthorizedResponse()
77→    }
78→    if (error instanceof Error && error.message === 'Forbidden') {
79→      return NextResponse.json({ error: 'Sem acesso ao espaço' }, { status: 403 })
80→    }
81→    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
82→  }
83→}
